import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Link } from "wouter";
import {
  Clock, Users, CheckCircle2, XCircle, AlertCircle,
  ArrowRight, Calendar, RefreshCw, Download, Search,
} from "lucide-react";

interface AttendanceRecord {
  id: string;
  employeeId: string;
  employeeName: string;
  branchId: string;
  date: string;
  checkInTime?: string;
  checkOutTime?: string;
  status: string;
  isLate: boolean;
  lateMinutes: number;
  workMinutes: number;
}

export default function AdminAttendance() {
  const { toast } = useToast();
  const [dateFilter, setDateFilter] = useState(new Date().toISOString().split("T")[0]);
  const [search, setSearch] = useState("");

  const { data: records = [], isLoading, refetch } = useQuery<AttendanceRecord[]>({
    queryKey: ["/api/admin/attendance", dateFilter],
    queryFn: () => fetch(`/api/admin/attendance?date=${dateFilter}`, { credentials: "include" }).then(r => r.json()),
    refetchInterval: 30000,
  });

  const filtered = records.filter(r =>
    !search || r.employeeName.includes(search)
  );

  const present = records.filter(r => r.checkInTime).length;
  const late = records.filter(r => r.isLate).length;
  const checkedOut = records.filter(r => r.checkOutTime).length;

  function fmtTime(iso?: string) {
    if (!iso) return "—";
    return new Date(iso).toLocaleTimeString("ar-SA", { hour: "2-digit", minute: "2-digit" });
  }

  function fmtMinutes(m: number) {
    if (!m) return "—";
    const h = Math.floor(m / 60);
    const min = m % 60;
    return h > 0 ? `${h}س ${min}د` : `${min}د`;
  }

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-6xl mx-auto p-6 space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Link href="/admin">
              <Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button>
            </Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">سجل الحضور والغياب</h1>
              <p className="text-sm text-gray-500">تتبع حضور الموظفين يومياً</p>
            </div>
          </div>
          <Button variant="outline" size="sm" onClick={() => refetch()}>
            <RefreshCw className="w-4 h-4 ml-1" /> تحديث
          </Button>
        </div>

        {/* Date filter + Search */}
        <div className="flex gap-3 flex-wrap">
          <Input type="date" value={dateFilter} onChange={e => setDateFilter(e.target.value)}
            className="w-48 bg-white" data-testid="input-date-filter" />
          <div className="relative flex-1 min-w-48">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <Input placeholder="ابحث عن موظف..." value={search} onChange={e => setSearch(e.target.value)}
              className="pr-9 bg-white" data-testid="input-search" />
          </div>
        </div>

        {/* Stats cards */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {[
            { label: "إجمالي الموظفين", value: records.length, icon: Users, color: "text-blue-600 bg-blue-50" },
            { label: "حاضر", value: present, icon: CheckCircle2, color: "text-green-600 bg-green-50" },
            { label: "متأخر", value: late, icon: AlertCircle, color: "text-amber-600 bg-amber-50" },
            { label: "انصرف", value: checkedOut, icon: Clock, color: "text-purple-600 bg-purple-50" },
          ].map(s => (
            <Card key={s.label} className="bg-white">
              <CardContent className="p-4">
                <div className="flex items-center gap-3">
                  <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${s.color}`}>
                    <s.icon className="w-5 h-5" />
                  </div>
                  <div>
                    <p className="text-2xl font-bold text-gray-900">{s.value}</p>
                    <p className="text-xs text-gray-500">{s.label}</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>

        {/* Table */}
        <Card className="bg-white">
          <CardHeader className="pb-3">
            <CardTitle className="text-gray-900 flex items-center gap-2">
              <Calendar className="w-5 h-5 text-[#6B3F2A]" />
              سجلات الحضور — {dateFilter}
            </CardTitle>
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
            ) : filtered.length === 0 ? (
              <div className="text-center py-12 text-gray-400">
                <Users className="w-12 h-12 mx-auto mb-3 opacity-30" />
                <p>لا توجد سجلات لهذا اليوم</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b text-right">
                      <th className="py-3 px-2 text-gray-500 font-medium">الموظف</th>
                      <th className="py-3 px-2 text-gray-500 font-medium">الحضور</th>
                      <th className="py-3 px-2 text-gray-500 font-medium">الانصراف</th>
                      <th className="py-3 px-2 text-gray-500 font-medium">مدة العمل</th>
                      <th className="py-3 px-2 text-gray-500 font-medium">الحالة</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {filtered.map(r => (
                      <tr key={r.id} className="hover:bg-gray-50" data-testid={`row-attendance-${r.id}`}>
                        <td className="py-3 px-2 font-medium text-gray-900">{r.employeeName || "—"}</td>
                        <td className="py-3 px-2 text-gray-600 font-mono">{fmtTime(r.checkInTime)}</td>
                        <td className="py-3 px-2 text-gray-600 font-mono">{fmtTime(r.checkOutTime)}</td>
                        <td className="py-3 px-2 text-gray-600">{fmtMinutes(r.workMinutes)}</td>
                        <td className="py-3 px-2">
                          {!r.checkInTime ? (
                            <Badge className="bg-red-100 text-red-700 border-0">غائب</Badge>
                          ) : r.isLate ? (
                            <Badge className="bg-amber-100 text-amber-700 border-0">متأخر {r.lateMinutes}د</Badge>
                          ) : (
                            <Badge className="bg-green-100 text-green-700 border-0">في الموعد</Badge>
                          )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useAuth } from "@/hooks/use-auth";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Link } from "wouter";
import {
  Clock, CheckCircle2, LogIn, LogOut, ArrowRight,
  Loader2, Calendar, FileText, RefreshCw,
} from "lucide-react";

interface AttendanceStatus {
  hasCheckedIn: boolean;
  hasCheckedOut: boolean;
  attendance: {
    id: string;
    checkInTime: string;
    checkOutTime?: string;
    isLate: boolean;
    lateMinutes: number;
  } | null;
}

export default function EmployeeAttendancePage() {
  const { user } = useAuth();
  const { toast } = useToast();
  const [status, setStatus] = useState<AttendanceStatus | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const t = setInterval(() => setNow(new Date()), 1000);
    fetchStatus();
    return () => clearInterval(t);
  }, []);

  async function fetchStatus() {
    try {
      const r = await fetch("/api/attendance/my-status", { credentials: "include" });
      if (r.ok) setStatus(await r.json());
    } catch {}
  }

  async function handleCheckIn() {
    setIsLoading(true);
    try {
      const r = await fetch("/api/attendance/check-in", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({}),
      });
      const data = await r.json();
      if (!r.ok) { toast({ title: "خطأ", description: data.error, variant: "destructive" }); return; }
      toast({ title: "✅ تم تسجيل الحضور", description: data.message });
      await fetchStatus();
    } catch { toast({ title: "خطأ", description: "فشل التسجيل", variant: "destructive" }); }
    finally { setIsLoading(false); }
  }

  async function handleCheckOut() {
    setIsLoading(true);
    try {
      const r = await fetch("/api/attendance/check-out", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({}),
      });
      const data = await r.json();
      if (!r.ok) { toast({ title: "خطأ", description: data.error, variant: "destructive" }); return; }
      toast({ title: "✅ تم تسجيل الانصراف", description: data.message });
      await fetchStatus();
    } catch { toast({ title: "خطأ", description: "فشل التسجيل", variant: "destructive" }); }
    finally { setIsLoading(false); }
  }

  const fmtTime = (iso?: string) => iso ? new Date(iso).toLocaleTimeString("ar-SA", { hour: "2-digit", minute: "2-digit" }) : "—";
  const timeStr = now.toLocaleTimeString("ar-SA", { hour: "2-digit", minute: "2-digit", second: "2-digit" });
  const dateStr = now.toLocaleDateString("ar-SA", { weekday: "long", year: "numeric", month: "long", day: "numeric" });

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#6B3F2A]/5 to-gray-50" dir="rtl">
      <div className="max-w-md mx-auto p-4 space-y-4">

        {/* Header */}
        <div className="flex items-center gap-3 pt-4">
          <Link href="/dashboard">
            <Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button>
          </Link>
          <div>
            <h1 className="text-xl font-bold text-[#6B3F2A]">تسجيل الحضور</h1>
            <p className="text-sm text-gray-500">أهلاً، {user?.name}</p>
          </div>
        </div>

        {/* Live Clock */}
        <Card className="bg-[#6B3F2A] text-white">
          <CardContent className="p-6 text-center">
            <p className="text-5xl font-mono font-bold mb-1">{timeStr}</p>
            <p className="text-[#6B3F2A]/30 text-sm">{dateStr}</p>
          </CardContent>
        </Card>

        {/* Today status */}
        <Card className="bg-white">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm text-gray-600 flex items-center gap-2">
              <Calendar className="w-4 h-4" /> حالة اليوم
            </CardTitle>
          </CardHeader>
          <CardContent className="grid grid-cols-2 gap-4">
            <div className="text-center p-3 bg-green-50 rounded-xl">
              <p className="text-xs text-gray-500 mb-1">وقت الحضور</p>
              <p className="text-lg font-bold text-green-700">{fmtTime(status?.attendance?.checkInTime)}</p>
            </div>
            <div className="text-center p-3 bg-blue-50 rounded-xl">
              <p className="text-xs text-gray-500 mb-1">وقت الانصراف</p>
              <p className="text-lg font-bold text-blue-700">{fmtTime(status?.attendance?.checkOutTime)}</p>
            </div>
          </CardContent>
        </Card>

        {/* Status badge */}
        {status?.attendance && (
          <div className="text-center">
            {status.attendance.isLate ? (
              <Badge className="bg-amber-100 text-amber-700 border-amber-200 text-sm px-4 py-1.5">
                متأخر {status.attendance.lateMinutes} دقيقة
              </Badge>
            ) : (
              <Badge className="bg-green-100 text-green-700 border-green-200 text-sm px-4 py-1.5">
                ✅ حضر في الوقت المحدد
              </Badge>
            )}
          </div>
        )}

        {/* Action button */}
        <div className="space-y-3">
          {!status?.hasCheckedIn ? (
            <Button
              onClick={handleCheckIn}
              disabled={isLoading}
              className="w-full h-16 text-xl font-bold bg-green-600 hover:bg-green-700 rounded-2xl shadow-lg"
              data-testid="button-check-in"
            >
              {isLoading ? <Loader2 className="w-6 h-6 animate-spin ml-2" /> : <LogIn className="w-6 h-6 ml-2" />}
              تسجيل الحضور
            </Button>
          ) : !status.hasCheckedOut ? (
            <Button
              onClick={handleCheckOut}
              disabled={isLoading}
              className="w-full h-16 text-xl font-bold bg-rose-600 hover:bg-rose-700 rounded-2xl shadow-lg"
              data-testid="button-check-out"
            >
              {isLoading ? <Loader2 className="w-6 h-6 animate-spin ml-2" /> : <LogOut className="w-6 h-6 ml-2" />}
              تسجيل الانصراف
            </Button>
          ) : (
            <div className="text-center p-6 bg-green-50 rounded-2xl border border-green-200">
              <CheckCircle2 className="w-12 h-12 text-green-600 mx-auto mb-2" />
              <p className="font-bold text-green-700">اكتمل تسجيل الحضور والانصراف</p>
              <p className="text-sm text-gray-500 mt-1">نراك غداً!</p>
            </div>
          )}

          <Button variant="outline" onClick={fetchStatus} className="w-full" data-testid="button-refresh">
            <RefreshCw className="w-4 h-4 ml-2" /> تحديث الحالة
          </Button>
        </div>

        {/* Leave request link */}
        <Link href="/employee/leave-request">
          <Button variant="ghost" className="w-full text-[#6B3F2A]" data-testid="link-leave-request">
            <FileText className="w-4 h-4 ml-2" /> تقديم طلب إجازة
          </Button>
        </Link>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Link } from "wouter";
import {
  ArrowRight, Calendar, CheckCircle2, XCircle, Clock,
  Users, AlertCircle, FileText,
} from "lucide-react";

interface LeaveRequest {
  id: string;
  employeeId: string;
  employeeName: string;
  type: string;
  startDate: string;
  endDate: string;
  numberOfDays: number;
  reason: string;
  status: "pending" | "approved" | "rejected";
  rejectionReason?: string;
  approvedBy?: string;
  createdAt: string;
}

const typeLabels: Record<string, string> = {
  annual: "إجازة سنوية",
  sick: "إجازة مرضية",
  emergency: "طارئة",
  other: "أخرى",
};

export default function AdminLeaveRequests() {
  const { toast } = useToast();
  const [statusFilter, setStatusFilter] = useState("all");
  const [rejectDialog, setRejectDialog] = useState<{ id: string; name: string } | null>(null);
  const [rejectionReason, setRejectionReason] = useState("");

  const { data: requests = [], isLoading } = useQuery<LeaveRequest[]>({
    queryKey: ["/api/leave-requests"],
  });

  const approveMutation = useMutation({
    mutationFn: (id: string) => apiRequest("PATCH", `/api/admin/leave-requests/${id}`, { status: "approved" }),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/leave-requests"] }); toast({ title: "تمت الموافقة على الطلب" }); },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const rejectMutation = useMutation({
    mutationFn: ({ id, reason }: { id: string; reason: string }) =>
      apiRequest("PATCH", `/api/admin/leave-requests/${id}`, { status: "rejected", rejectionReason: reason }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/leave-requests"] });
      setRejectDialog(null); setRejectionReason("");
      toast({ title: "تم رفض الطلب" });
    },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const filtered = statusFilter === "all" ? requests : requests.filter(r => r.status === statusFilter);
  const pending = requests.filter(r => r.status === "pending").length;

  const statusBadge = (status: string) => {
    if (status === "approved") return <Badge className="bg-green-100 text-green-700 border-0">موافق</Badge>;
    if (status === "rejected") return <Badge className="bg-red-100 text-red-700 border-0">مرفوض</Badge>;
    return <Badge className="bg-amber-100 text-amber-700 border-0">قيد الانتظار</Badge>;
  };

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-5xl mx-auto p-6 space-y-6">
        <div className="flex items-center gap-3">
          <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
          <div>
            <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
              طلبات الإجازات
              {pending > 0 && <Badge className="bg-amber-500 text-white">{pending} معلّق</Badge>}
            </h1>
            <p className="text-sm text-gray-500">إدارة طلبات إجازة الموظفين</p>
          </div>
        </div>

        {/* Filter tabs */}
        <div className="flex gap-2 flex-wrap">
          {[
            { key: "all", label: "الكل" },
            { key: "pending", label: "قيد الانتظار" },
            { key: "approved", label: "موافق" },
            { key: "rejected", label: "مرفوض" },
          ].map(f => (
            <Button
              key={f.key} size="sm"
              variant={statusFilter === f.key ? "default" : "outline"}
              onClick={() => setStatusFilter(f.key)}
              className={statusFilter === f.key ? "bg-[#6B3F2A] text-white" : ""}
              data-testid={`filter-${f.key}`}
            >
              {f.label}
            </Button>
          ))}
        </div>

        {/* Requests */}
        {isLoading ? (
          <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-12 text-gray-400">
            <FileText className="w-12 h-12 mx-auto mb-3 opacity-30" />
            <p>لا توجد طلبات</p>
          </div>
        ) : (
          <div className="space-y-3">
            {filtered.map(r => (
              <Card key={r.id} className="bg-white" data-testid={`card-leave-${r.id}`}>
                <CardContent className="p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <p className="font-bold text-gray-900">{r.employeeName}</p>
                        {statusBadge(r.status)}
                        <Badge variant="outline" className="text-xs">{typeLabels[r.type] || r.type}</Badge>
                      </div>
                      <div className="text-sm text-gray-600 space-y-0.5">
                        <p>من {new Date(r.startDate).toLocaleDateString("ar-SA")} إلى {new Date(r.endDate).toLocaleDateString("ar-SA")} ({r.numberOfDays} أيام)</p>
                        <p className="text-gray-500">السبب: {r.reason}</p>
                        {r.rejectionReason && <p className="text-red-500 text-xs">سبب الرفض: {r.rejectionReason}</p>}
                        {r.approvedBy && <p className="text-gray-400 text-xs">بواسطة: {r.approvedBy}</p>}
                      </div>
                    </div>
                    {r.status === "pending" && (
                      <div className="flex gap-2 shrink-0">
                        <Button
                          size="sm"
                          className="bg-green-600 hover:bg-green-700 text-white"
                          onClick={() => approveMutation.mutate(r.id)}
                          disabled={approveMutation.isPending}
                          data-testid={`button-approve-${r.id}`}
                        >
                          <CheckCircle2 className="w-4 h-4 ml-1" /> موافقة
                        </Button>
                        <Button
                          size="sm" variant="outline"
                          className="border-red-200 text-red-600 hover:bg-red-50"
                          onClick={() => setRejectDialog({ id: r.id, name: r.employeeName })}
                          data-testid={`button-reject-${r.id}`}
                        >
                          <XCircle className="w-4 h-4 ml-1" /> رفض
                        </Button>
                      </div>
                    )}
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      {/* Reject dialog */}
      <Dialog open={!!rejectDialog} onOpenChange={() => { setRejectDialog(null); setRejectionReason(""); }}>
        <DialogContent dir="rtl">
          <DialogHeader>
            <DialogTitle>رفض طلب إجازة — {rejectDialog?.name}</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <p className="text-sm text-gray-600">يرجى إدخال سبب الرفض (اختياري)</p>
            <Textarea
              value={rejectionReason}
              onChange={e => setRejectionReason(e.target.value)}
              placeholder="سبب الرفض..."
              className="h-24"
              data-testid="input-rejection-reason"
            />
          </div>
          <DialogFooter className="gap-2">
            <Button variant="outline" onClick={() => { setRejectDialog(null); setRejectionReason(""); }}>إلغاء</Button>
            <Button
              className="bg-red-600 hover:bg-red-700 text-white"
              onClick={() => rejectDialog && rejectMutation.mutate({ id: rejectDialog.id, reason: rejectionReason })}
              disabled={rejectMutation.isPending}
              data-testid="button-confirm-reject"
            >
              تأكيد الرفض
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Link } from "wouter";
import { ArrowRight, Calendar, FileText, CheckCircle2, XCircle, Clock, Loader2 } from "lucide-react";

interface LeaveRequest {
  id: string;
  type: string;
  startDate: string;
  endDate: string;
  numberOfDays: number;
  reason: string;
  status: "pending" | "approved" | "rejected";
  rejectionReason?: string;
  createdAt: string;
}

const typeLabels: Record<string, string> = {
  annual: "إجازة سنوية",
  sick: "إجازة مرضية",
  emergency: "طارئة",
  other: "أخرى",
};

export default function EmployeeLeaveRequest() {
  const { toast } = useToast();
  const [isLoading, setIsLoading] = useState(false);
  const [requests, setRequests] = useState<LeaveRequest[]>([]);
  const [loadingReqs, setLoadingReqs] = useState(true);
  const [form, setForm] = useState({ type: "annual", startDate: "", endDate: "", reason: "" });

  useEffect(() => { fetchRequests(); }, []);

  async function fetchRequests() {
    try {
      const r = await fetch("/api/leave-requests", { credentials: "include" });
      if (r.ok) setRequests(await r.json());
    } catch {} finally { setLoadingReqs(false); }
  }

  const days = (() => {
    if (!form.startDate || !form.endDate) return 0;
    const diff = new Date(form.endDate).getTime() - new Date(form.startDate).getTime();
    return Math.ceil(diff / (1000 * 60 * 60 * 24)) + 1;
  })();

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!form.startDate || !form.endDate || !form.reason.trim()) {
      toast({ title: "خطأ", description: "يرجى ملء جميع الحقول", variant: "destructive" }); return;
    }
    if (new Date(form.endDate) < new Date(form.startDate)) {
      toast({ title: "خطأ", description: "تاريخ النهاية يجب أن يكون بعد البداية", variant: "destructive" }); return;
    }
    setIsLoading(true);
    try {
      const r = await fetch("/api/leave-requests", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify(form),
      });
      const data = await r.json();
      if (!r.ok) { toast({ title: "خطأ", description: data.error, variant: "destructive" }); return; }
      toast({ title: "✅ تم إرسال طلب الإجازة بنجاح" });
      setForm({ type: "annual", startDate: "", endDate: "", reason: "" });
      fetchRequests();
    } catch { toast({ title: "خطأ", variant: "destructive" }); }
    finally { setIsLoading(false); }
  }

  const statusIcon = (s: string) => {
    if (s === "approved") return <CheckCircle2 className="w-4 h-4 text-green-600" />;
    if (s === "rejected") return <XCircle className="w-4 h-4 text-red-600" />;
    return <Clock className="w-4 h-4 text-amber-500" />;
  };

  const statusText = (s: string) => s === "approved" ? "موافق" : s === "rejected" ? "مرفوض" : "قيد الانتظار";
  const statusColor = (s: string) => s === "approved" ? "bg-green-100 text-green-700" : s === "rejected" ? "bg-red-100 text-red-700" : "bg-amber-100 text-amber-700";

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-2xl mx-auto p-4 space-y-5 pb-10">
        <div className="flex items-center gap-3 pt-4">
          <Link href="/employee/attendance">
            <Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button>
          </Link>
          <div>
            <h1 className="text-xl font-bold text-[#6B3F2A]">طلب إجازة</h1>
            <p className="text-sm text-gray-500">تقديم وتتبع طلبات الإجازة</p>
          </div>
        </div>

        {/* Form */}
        <Card className="bg-white">
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2">
              <FileText className="w-5 h-5 text-[#6B3F2A]" /> نموذج طلب إجازة
            </CardTitle>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <Label>نوع الإجازة</Label>
                <Select value={form.type} onValueChange={v => setForm(f => ({ ...f, type: v }))}>
                  <SelectTrigger data-testid="select-leave-type">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    {Object.entries(typeLabels).map(([k, v]) => (
                      <SelectItem key={k} value={k}>{v}</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <Label>تاريخ البداية</Label>
                  <Input type="date" value={form.startDate} onChange={e => setForm(f => ({ ...f, startDate: e.target.value }))}
                    data-testid="input-start-date" />
                </div>
                <div>
                  <Label>تاريخ النهاية</Label>
                  <Input type="date" value={form.endDate} onChange={e => setForm(f => ({ ...f, endDate: e.target.value }))}
                    data-testid="input-end-date" />
                </div>
              </div>
              {days > 0 && (
                <div className="bg-[#6B3F2A]/5 rounded-xl p-3 text-center">
                  <span className="text-sm text-gray-600">عدد الأيام: </span>
                  <span className="font-bold text-[#6B3F2A]">{days} أيام</span>
                </div>
              )}
              <div>
                <Label>سبب الإجازة</Label>
                <Textarea value={form.reason} onChange={e => setForm(f => ({ ...f, reason: e.target.value }))}
                  placeholder="اذكر سبب الإجازة..." className="h-24 resize-none"
                  data-testid="textarea-reason" />
              </div>
              <Button type="submit" disabled={isLoading} className="w-full bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white"
                data-testid="button-submit">
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin ml-2" /> : null}
                تقديم الطلب
              </Button>
            </form>
          </CardContent>
        </Card>

        {/* History */}
        <Card className="bg-white">
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2">
              <Calendar className="w-5 h-5 text-[#6B3F2A]" /> سجل الطلبات
            </CardTitle>
          </CardHeader>
          <CardContent>
            {loadingReqs ? (
              <p className="text-center text-gray-400 py-6">جاري التحميل...</p>
            ) : requests.length === 0 ? (
              <p className="text-center text-gray-400 py-6">لا توجد طلبات سابقة</p>
            ) : (
              <div className="space-y-3">
                {requests.map(r => (
                  <div key={r.id} className="border border-gray-100 rounded-xl p-3" data-testid={`card-request-${r.id}`}>
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-sm font-medium">{typeLabels[r.type] || r.type}</span>
                      <Badge className={`${statusColor(r.status)} border-0 text-xs`}>
                        <span className="flex items-center gap-1">{statusIcon(r.status)} {statusText(r.status)}</span>
                      </Badge>
                    </div>
                    <p className="text-xs text-gray-500">{new Date(r.startDate).toLocaleDateString("ar-SA")} — {new Date(r.endDate).toLocaleDateString("ar-SA")} ({r.numberOfDays} أيام)</p>
                    <p className="text-xs text-gray-400 mt-0.5">{r.reason}</p>
                    {r.rejectionReason && <p className="text-xs text-red-500 mt-1">سبب الرفض: {r.rejectionReason}</p>}
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Link } from "wouter";
import {
  ArrowRight, Plus, Edit, Trash2, Search, Package,
  AlertTriangle, Coffee, Box, Droplet, Loader2, RefreshCw, TrendingDown,
} from "lucide-react";

interface RawMaterial {
  id: string;
  code: string;
  nameAr: string;
  nameEn?: string;
  category: string;
  unit: string;
  unitCost: number;
  currentStock: number;
  minStockLevel: number;
  maxStockLevel?: number;
  isActive: boolean;
}

const categories = [
  { value: "ingredient", label: "مكون", color: "bg-green-100 text-green-800" },
  { value: "packaging", label: "تغليف", color: "bg-blue-100 text-blue-800" },
  { value: "equipment", label: "معدات", color: "bg-slate-100 text-slate-800" },
  { value: "consumable", label: "مستهلكات", color: "bg-orange-100 text-orange-800" },
  { value: "other", label: "أخرى", color: "bg-gray-100 text-gray-800" },
];

const units = ["g", "kg", "ml", "liter", "piece", "box", "bag"];
const unitLabels: Record<string, string> = { g: "جرام", kg: "كيلو", ml: "مل", liter: "لتر", piece: "قطعة", box: "صندوق", bag: "كيس" };

const emptyForm = { code: "", nameAr: "", nameEn: "", category: "ingredient", unit: "g", unitCost: 0, currentStock: 0, minStockLevel: 0, maxStockLevel: 0 };

export default function AdminRawMaterials() {
  const { toast } = useToast();
  const [search, setSearch] = useState("");
  const [catFilter, setCatFilter] = useState("all");
  const [showDialog, setShowDialog] = useState(false);
  const [editItem, setEditItem] = useState<RawMaterial | null>(null);
  const [stockDialog, setStockDialog] = useState<RawMaterial | null>(null);
  const [stockDelta, setStockDelta] = useState(0);
  const [form, setForm] = useState(emptyForm);

  const { data: items = [], isLoading, refetch } = useQuery<RawMaterial[]>({
    queryKey: ["/api/inventory/raw-materials"],
  });

  const createMutation = useMutation({
    mutationFn: (data: typeof form) => apiRequest("POST", "/api/inventory/raw-materials", data),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/raw-materials"] }); setShowDialog(false); setForm(emptyForm); toast({ title: "تمت إضافة المادة بنجاح" }); },
    onError: (e: any) => toast({ title: e.message || "خطأ", variant: "destructive" }),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: any }) => apiRequest("PUT", `/api/inventory/raw-materials/${id}`, data),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/raw-materials"] }); setShowDialog(false); setEditItem(null); setForm(emptyForm); toast({ title: "تم التحديث بنجاح" }); },
    onError: (e: any) => toast({ title: e.message || "خطأ", variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiRequest("DELETE", `/api/inventory/raw-materials/${id}`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/raw-materials"] }); toast({ title: "تم الحذف" }); },
    onError: () => toast({ title: "خطأ في الحذف", variant: "destructive" }),
  });

  const stockMutation = useMutation({
    mutationFn: ({ id, delta }: { id: string; delta: number }) => apiRequest("PATCH", `/api/inventory/raw-materials/${id}/stock`, { delta }),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/raw-materials"] }); setStockDialog(null); setStockDelta(0); toast({ title: "تم تعديل المخزون" }); },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const openEdit = (item: RawMaterial) => {
    setEditItem(item);
    setForm({ code: item.code, nameAr: item.nameAr, nameEn: item.nameEn || "", category: item.category, unit: item.unit, unitCost: item.unitCost, currentStock: item.currentStock, minStockLevel: item.minStockLevel, maxStockLevel: item.maxStockLevel || 0 });
    setShowDialog(true);
  };

  const handleSubmit = () => {
    if (!form.nameAr.trim()) { toast({ title: "الاسم مطلوب", variant: "destructive" }); return; }
    if (editItem) updateMutation.mutate({ id: editItem.id, data: form });
    else createMutation.mutate(form);
  };

  const filtered = items.filter(i => {
    if (catFilter !== "all" && i.category !== catFilter) return false;
    if (search && !i.nameAr.includes(search) && !i.nameEn?.includes(search)) return false;
    return true;
  });

  const alerts = items.filter(i => i.minStockLevel > 0 && i.currentStock <= i.minStockLevel);
  const cat = (key: string) => categories.find(c => c.value === key);

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-6xl mx-auto p-6 space-y-6">
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">المواد الخام</h1>
              <p className="text-sm text-gray-500">إدارة مخزون المكونات والمواد</p>
            </div>
          </div>
          <Button onClick={() => { setEditItem(null); setForm(emptyForm); setShowDialog(true); }} className="bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white" data-testid="button-add">
            <Plus className="w-4 h-4 ml-1" /> إضافة مادة
          </Button>
        </div>

        {/* Alerts */}
        {alerts.length > 0 && (
          <div className="bg-amber-50 border border-amber-200 rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <AlertTriangle className="w-5 h-5 text-amber-600" />
              <p className="font-bold text-amber-800">تنبيه مخزون منخفض — {alerts.length} مادة</p>
            </div>
            <div className="flex flex-wrap gap-2">
              {alerts.map(a => (
                <Badge key={a.id} className="bg-amber-100 text-amber-800 border-amber-200">{a.nameAr} ({a.currentStock} {unitLabels[a.unit] || a.unit})</Badge>
              ))}
            </div>
          </div>
        )}

        {/* Filters */}
        <div className="flex gap-3 flex-wrap">
          <div className="relative flex-1 min-w-48">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <Input placeholder="بحث..." value={search} onChange={e => setSearch(e.target.value)} className="pr-9 bg-white" />
          </div>
          <Select value={catFilter} onValueChange={setCatFilter}>
            <SelectTrigger className="w-40 bg-white"><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="all">كل الفئات</SelectItem>
              {categories.map(c => <SelectItem key={c.value} value={c.value}>{c.label}</SelectItem>)}
            </SelectContent>
          </Select>
        </div>

        {/* Table */}
        <Card className="bg-white">
          <CardContent className="p-0">
            {isLoading ? (
              <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
            ) : filtered.length === 0 ? (
              <div className="text-center py-12 text-gray-400">
                <Package className="w-12 h-12 mx-auto mb-3 opacity-30" />
                <p>لا توجد مواد</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-gray-50">
                    <tr className="text-right">
                      <th className="py-3 px-4 text-gray-500 font-medium">الاسم</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">الفئة</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">المخزون الحالي</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">الحد الأدنى</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">تكلفة الوحدة</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">الإجراءات</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {filtered.map(item => {
                      const isLow = item.minStockLevel > 0 && item.currentStock <= item.minStockLevel;
                      return (
                        <tr key={item.id} className={`hover:bg-gray-50 ${isLow ? "bg-amber-50/40" : ""}`} data-testid={`row-material-${item.id}`}>
                          <td className="py-3 px-4">
                            <p className="font-medium text-gray-900">{item.nameAr}</p>
                            {item.nameEn && <p className="text-xs text-gray-400">{item.nameEn}</p>}
                          </td>
                          <td className="py-3 px-4">
                            <Badge className={`${cat(item.category)?.color} border-0 text-xs`}>{cat(item.category)?.label}</Badge>
                          </td>
                          <td className="py-3 px-4">
                            <div className="flex items-center gap-2">
                              {isLow && <TrendingDown className="w-4 h-4 text-amber-500" />}
                              <span className={`font-mono font-bold ${isLow ? "text-amber-600" : "text-gray-900"}`}>
                                {item.currentStock} {unitLabels[item.unit] || item.unit}
                              </span>
                            </div>
                          </td>
                          <td className="py-3 px-4 text-gray-600 font-mono">{item.minStockLevel} {unitLabels[item.unit] || item.unit}</td>
                          <td className="py-3 px-4 text-gray-600 font-mono">{item.unitCost} ر.س</td>
                          <td className="py-3 px-4">
                            <div className="flex gap-1">
                              <Button size="sm" variant="outline" className="h-7 text-xs" onClick={() => setStockDialog(item)} data-testid={`button-stock-${item.id}`}>تعديل كمية</Button>
                              <Button size="icon" variant="ghost" className="h-7 w-7" onClick={() => openEdit(item)} data-testid={`button-edit-${item.id}`}><Edit className="w-3.5 h-3.5" /></Button>
                              <Button size="icon" variant="ghost" className="h-7 w-7 text-red-500" onClick={() => confirm("حذف هذه المادة؟") && deleteMutation.mutate(item.id)} data-testid={`button-delete-${item.id}`}><Trash2 className="w-3.5 h-3.5" /></Button>
                            </div>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Add/Edit Dialog */}
      <Dialog open={showDialog} onOpenChange={v => { setShowDialog(v); if (!v) { setEditItem(null); setForm(emptyForm); } }}>
        <DialogContent dir="rtl" className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{editItem ? "تعديل مادة خام" : "إضافة مادة خام جديدة"}</DialogTitle>
          </DialogHeader>
          <div className="grid grid-cols-2 gap-3">
            <div className="col-span-2">
              <Label>الاسم بالعربية *</Label>
              <Input value={form.nameAr} onChange={e => setForm(f => ({ ...f, nameAr: e.target.value }))} placeholder="مثال: حبوب قهوة إثيوبية" data-testid="input-name-ar" />
            </div>
            <div>
              <Label>الاسم بالإنجليزية</Label>
              <Input value={form.nameEn} onChange={e => setForm(f => ({ ...f, nameEn: e.target.value }))} data-testid="input-name-en" />
            </div>
            <div>
              <Label>الكود</Label>
              <Input value={form.code} onChange={e => setForm(f => ({ ...f, code: e.target.value }))} placeholder="MAT-001" data-testid="input-code" />
            </div>
            <div>
              <Label>الفئة</Label>
              <Select value={form.category} onValueChange={v => setForm(f => ({ ...f, category: v }))}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{categories.map(c => <SelectItem key={c.value} value={c.value}>{c.label}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>وحدة القياس</Label>
              <Select value={form.unit} onValueChange={v => setForm(f => ({ ...f, unit: v }))}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{units.map(u => <SelectItem key={u} value={u}>{unitLabels[u]}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>تكلفة الوحدة (ر.س)</Label>
              <Input type="number" min="0" step="0.01" value={form.unitCost} onChange={e => setForm(f => ({ ...f, unitCost: Number(e.target.value) }))} data-testid="input-unit-cost" />
            </div>
            <div>
              <Label>المخزون الحالي</Label>
              <Input type="number" min="0" value={form.currentStock} onChange={e => setForm(f => ({ ...f, currentStock: Number(e.target.value) }))} data-testid="input-current-stock" />
            </div>
            <div>
              <Label>الحد الأدنى للتنبيه</Label>
              <Input type="number" min="0" value={form.minStockLevel} onChange={e => setForm(f => ({ ...f, minStockLevel: Number(e.target.value) }))} data-testid="input-min-stock" />
            </div>
            <div>
              <Label>الحد الأقصى</Label>
              <Input type="number" min="0" value={form.maxStockLevel} onChange={e => setForm(f => ({ ...f, maxStockLevel: Number(e.target.value) }))} data-testid="input-max-stock" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowDialog(false)}>إلغاء</Button>
            <Button onClick={handleSubmit} disabled={createMutation.isPending || updateMutation.isPending} className="bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white" data-testid="button-save">
              {(createMutation.isPending || updateMutation.isPending) && <Loader2 className="w-4 h-4 animate-spin ml-2" />}
              {editItem ? "حفظ التغييرات" : "إضافة"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Stock Adjust Dialog */}
      <Dialog open={!!stockDialog} onOpenChange={v => { if (!v) { setStockDialog(null); setStockDelta(0); } }}>
        <DialogContent dir="rtl" className="max-w-sm">
          <DialogHeader>
            <DialogTitle>تعديل مخزون — {stockDialog?.nameAr}</DialogTitle>
          </DialogHeader>
          <div className="space-y-3">
            <p className="text-sm text-gray-600">المخزون الحالي: <span className="font-bold">{stockDialog?.currentStock} {stockDialog ? unitLabels[stockDialog.unit] : ""}</span></p>
            <div>
              <Label>الكمية (موجب للإضافة، سالب للخصم)</Label>
              <Input type="number" value={stockDelta} onChange={e => setStockDelta(Number(e.target.value))} data-testid="input-stock-delta" />
            </div>
            {stockDelta !== 0 && (
              <p className="text-sm text-blue-600">المخزون الجديد: {Math.max(0, (stockDialog?.currentStock || 0) + stockDelta)} {stockDialog ? unitLabels[stockDialog.unit] : ""}</p>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => { setStockDialog(null); setStockDelta(0); }}>إلغاء</Button>
            <Button onClick={() => stockDialog && stockMutation.mutate({ id: stockDialog.id, delta: stockDelta })} disabled={stockMutation.isPending || stockDelta === 0} className="bg-[#6B3F2A] text-white" data-testid="button-confirm-stock">
              تأكيد
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Link } from "wouter";
import { ArrowRight, Plus, Edit, Trash2, Search, Phone, Mail, MapPin, Star, Loader2, Store } from "lucide-react";

interface Supplier {
  id: string;
  name: string;
  nameEn?: string;
  contactPerson: string;
  phone: string;
  email: string;
  address: string;
  categories: string[];
  paymentTerms: string;
  rating: number;
  isActive: boolean;
  notes: string;
}

const empty = { name: "", nameEn: "", contactPerson: "", phone: "", email: "", address: "", categories: [], paymentTerms: "", rating: 0, isActive: true, notes: "" };

export default function AdminSuppliers() {
  const { toast } = useToast();
  const [search, setSearch] = useState("");
  const [showDialog, setShowDialog] = useState(false);
  const [editItem, setEditItem] = useState<Supplier | null>(null);
  const [form, setForm] = useState<any>(empty);

  const { data: suppliers = [], isLoading } = useQuery<Supplier[]>({ queryKey: ["/api/inventory/suppliers"] });

  const createMutation = useMutation({
    mutationFn: (d: any) => apiRequest("POST", "/api/inventory/suppliers", d),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/suppliers"] }); setShowDialog(false); setForm(empty); toast({ title: "تمت إضافة المورد" }); },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: any }) => apiRequest("PUT", `/api/inventory/suppliers/${id}`, data),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/suppliers"] }); setShowDialog(false); setEditItem(null); setForm(empty); toast({ title: "تم التحديث" }); },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiRequest("DELETE", `/api/inventory/suppliers/${id}`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/suppliers"] }); toast({ title: "تم الحذف" }); },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const openEdit = (s: Supplier) => { setEditItem(s); setForm({ ...s }); setShowDialog(true); };
  const handleSubmit = () => {
    if (!form.name.trim()) { toast({ title: "اسم المورد مطلوب", variant: "destructive" }); return; }
    if (editItem) updateMutation.mutate({ id: editItem.id, data: form });
    else createMutation.mutate(form);
  };

  const filtered = suppliers.filter(s => !search || s.name.includes(search) || s.phone.includes(search));

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-5xl mx-auto p-6 space-y-6">
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">الموردون</h1>
              <p className="text-sm text-gray-500">إدارة موردي المواد والمكونات</p>
            </div>
          </div>
          <Button onClick={() => { setEditItem(null); setForm(empty); setShowDialog(true); }} className="bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white" data-testid="button-add-supplier">
            <Plus className="w-4 h-4 ml-1" /> إضافة مورد
          </Button>
        </div>

        <div className="relative">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <Input value={search} onChange={e => setSearch(e.target.value)} placeholder="بحث بالاسم أو الهاتف..." className="pr-9 bg-white" />
        </div>

        {isLoading ? (
          <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-12 text-gray-400">
            <Store className="w-12 h-12 mx-auto mb-3 opacity-30" />
            <p>لا يوجد موردون</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {filtered.map(s => (
              <Card key={s.id} className="bg-white" data-testid={`card-supplier-${s.id}`}>
                <CardContent className="p-4">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <h3 className="font-bold text-gray-900">{s.name}</h3>
                        {!s.isActive && <Badge className="bg-red-100 text-red-700 border-0 text-xs">غير نشط</Badge>}
                      </div>
                      {s.contactPerson && <p className="text-sm text-gray-600">{s.contactPerson}</p>}
                      <div className="mt-2 space-y-1">
                        {s.phone && <p className="text-xs text-gray-500 flex items-center gap-1"><Phone className="w-3 h-3" /> {s.phone}</p>}
                        {s.email && <p className="text-xs text-gray-500 flex items-center gap-1"><Mail className="w-3 h-3" /> {s.email}</p>}
                        {s.address && <p className="text-xs text-gray-500 flex items-center gap-1"><MapPin className="w-3 h-3" /> {s.address}</p>}
                      </div>
                      {s.paymentTerms && <p className="text-xs text-blue-600 mt-2">شروط الدفع: {s.paymentTerms}</p>}
                    </div>
                    <div className="flex gap-1 shrink-0">
                      <Button size="icon" variant="ghost" className="h-8 w-8" onClick={() => openEdit(s)} data-testid={`button-edit-${s.id}`}><Edit className="w-3.5 h-3.5" /></Button>
                      <Button size="icon" variant="ghost" className="h-8 w-8 text-red-500" onClick={() => confirm("حذف هذا المورد؟") && deleteMutation.mutate(s.id)} data-testid={`button-delete-${s.id}`}><Trash2 className="w-3.5 h-3.5" /></Button>
                    </div>
                  </div>
                  {s.notes && <p className="text-xs text-gray-400 mt-3 border-t border-gray-100 pt-2">{s.notes}</p>}
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      <Dialog open={showDialog} onOpenChange={v => { setShowDialog(v); if (!v) { setEditItem(null); setForm(empty); } }}>
        <DialogContent dir="rtl" className="max-w-lg">
          <DialogHeader><DialogTitle>{editItem ? "تعديل مورد" : "إضافة مورد جديد"}</DialogTitle></DialogHeader>
          <div className="grid grid-cols-2 gap-3 max-h-96 overflow-y-auto">
            <div className="col-span-2"><Label>اسم المورد *</Label><Input value={form.name} onChange={e => setForm((f: any) => ({ ...f, name: e.target.value }))} data-testid="input-supplier-name" /></div>
            <div><Label>مسؤول التواصل</Label><Input value={form.contactPerson} onChange={e => setForm((f: any) => ({ ...f, contactPerson: e.target.value }))} /></div>
            <div><Label>الهاتف</Label><Input value={form.phone} onChange={e => setForm((f: any) => ({ ...f, phone: e.target.value }))} /></div>
            <div><Label>البريد الإلكتروني</Label><Input value={form.email} onChange={e => setForm((f: any) => ({ ...f, email: e.target.value }))} /></div>
            <div><Label>العنوان</Label><Input value={form.address} onChange={e => setForm((f: any) => ({ ...f, address: e.target.value }))} /></div>
            <div className="col-span-2"><Label>شروط الدفع</Label><Input value={form.paymentTerms} onChange={e => setForm((f: any) => ({ ...f, paymentTerms: e.target.value }))} placeholder="مثال: 30 يوم" /></div>
            <div className="col-span-2"><Label>ملاحظات</Label><Textarea value={form.notes} onChange={e => setForm((f: any) => ({ ...f, notes: e.target.value }))} className="h-20 resize-none" /></div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowDialog(false)}>إلغاء</Button>
            <Button onClick={handleSubmit} disabled={createMutation.isPending || updateMutation.isPending} className="bg-[#6B3F2A] text-white" data-testid="button-save-supplier">
              {(createMutation.isPending || updateMutation.isPending) && <Loader2 className="w-4 h-4 animate-spin ml-2" />}
              {editItem ? "حفظ" : "إضافة"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Link } from "wouter";
import { ArrowRight, Plus, Gift, Copy, Search, ToggleLeft, ToggleRight, Loader2, CheckCircle2 } from "lucide-react";

interface GiftCard {
  id: string;
  code: string;
  initialBalance: number;
  currentBalance: number;
  isActive: boolean;
  expiryDate?: string;
  recipientName?: string;
  recipientPhone?: string;
  createdAt: string;
  transactions: any[];
}

export default function AdminGiftCards() {
  const { toast } = useToast();
  const [search, setSearch] = useState("");
  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState({ initialBalance: 100, expiryDate: "", recipientName: "", recipientPhone: "" });
  const [copied, setCopied] = useState<string | null>(null);

  const { data: cards = [], isLoading } = useQuery<GiftCard[]>({ queryKey: ["/api/admin/gift-cards"] });

  const createMutation = useMutation({
    mutationFn: (d: typeof form) => apiRequest("POST", "/api/admin/gift-cards", d),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/gift-cards"] });
      setShowCreate(false);
      setForm({ initialBalance: 100, expiryDate: "", recipientName: "", recipientPhone: "" });
      toast({ title: "✅ تم إنشاء بطاقة الهدية" });
    },
    onError: (e: any) => toast({ title: e.message || "خطأ", variant: "destructive" }),
  });

  const toggleMutation = useMutation({
    mutationFn: (id: string) => apiRequest("PATCH", `/api/admin/gift-cards/${id}/toggle`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/admin/gift-cards"] }); toast({ title: "تم التحديث" }); },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const copyCode = (code: string) => {
    navigator.clipboard.writeText(code).then(() => {
      setCopied(code);
      setTimeout(() => setCopied(null), 2000);
    });
  };

  const filtered = cards.filter(c => !search || c.code.includes(search.toUpperCase()) || c.recipientName?.includes(search) || c.recipientPhone?.includes(search));

  const totalIssued = cards.reduce((s, c) => s + c.initialBalance, 0);
  const totalUsed = cards.reduce((s, c) => s + (c.initialBalance - c.currentBalance), 0);
  const activeCards = cards.filter(c => c.isActive).length;

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-5xl mx-auto p-6 space-y-6">
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">بطاقات الهدايا</h1>
              <p className="text-sm text-gray-500">إنشاء وإدارة بطاقات الهدايا</p>
            </div>
          </div>
          <Button onClick={() => setShowCreate(true)} className="bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white" data-testid="button-create-card">
            <Plus className="w-4 h-4 ml-1" /> بطاقة جديدة
          </Button>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-3 gap-4">
          {[
            { label: "إجمالي البطاقات", value: cards.length, color: "text-blue-600 bg-blue-50" },
            { label: "إجمالي المبالغ (ر.س)", value: totalIssued.toFixed(0), color: "text-green-600 bg-green-50" },
            { label: "مبالغ مستخدمة (ر.س)", value: totalUsed.toFixed(0), color: "text-orange-600 bg-orange-50" },
          ].map(s => (
            <Card key={s.label} className="bg-white">
              <CardContent className="p-4 text-center">
                <p className={`text-2xl font-bold ${s.color.split(" ")[0]}`}>{s.value}</p>
                <p className="text-xs text-gray-500 mt-1">{s.label}</p>
              </CardContent>
            </Card>
          ))}
        </div>

        {/* Search */}
        <div className="relative">
          <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <Input value={search} onChange={e => setSearch(e.target.value)} placeholder="بحث بالكود أو الاسم..." className="pr-9 bg-white" />
        </div>

        {/* Cards list */}
        {isLoading ? (
          <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
        ) : filtered.length === 0 ? (
          <div className="text-center py-12 text-gray-400">
            <Gift className="w-12 h-12 mx-auto mb-3 opacity-30" />
            <p>لا توجد بطاقات هدايا</p>
          </div>
        ) : (
          <div className="space-y-3">
            {filtered.map(card => {
              const usedPercent = card.initialBalance > 0 ? ((card.initialBalance - card.currentBalance) / card.initialBalance) * 100 : 0;
              return (
                <Card key={card.id} className={`bg-white ${!card.isActive ? "opacity-60" : ""}`} data-testid={`card-gift-${card.id}`}>
                  <CardContent className="p-4">
                    <div className="flex items-center justify-between gap-3">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-[#6B3F2A]/10 rounded-xl flex items-center justify-center">
                          <Gift className="w-5 h-5 text-[#6B3F2A]" />
                        </div>
                        <div>
                          <div className="flex items-center gap-2">
                            <code className="font-bold text-[#6B3F2A] text-sm">{card.code}</code>
                            <button onClick={() => copyCode(card.code)} className="text-gray-400 hover:text-gray-600" data-testid={`button-copy-${card.id}`}>
                              {copied === card.code ? <CheckCircle2 className="w-3.5 h-3.5 text-green-500" /> : <Copy className="w-3.5 h-3.5" />}
                            </button>
                            <Badge className={card.isActive ? "bg-green-100 text-green-700 border-0 text-xs" : "bg-gray-100 text-gray-500 border-0 text-xs"}>
                              {card.isActive ? "نشطة" : "موقوفة"}
                            </Badge>
                          </div>
                          {card.recipientName && <p className="text-xs text-gray-500 mt-0.5">{card.recipientName} {card.recipientPhone && `(${card.recipientPhone})`}</p>}
                        </div>
                      </div>
                      <div className="text-center">
                        <p className="text-lg font-bold text-gray-900">{card.currentBalance} <span className="text-xs text-gray-400">/ {card.initialBalance} ر.س</span></p>
                        <div className="w-24 h-1.5 bg-gray-200 rounded-full mt-1 mx-auto">
                          <div className="h-full bg-[#6B3F2A] rounded-full" style={{ width: `${100 - usedPercent}%` }} />
                        </div>
                        <p className="text-xs text-gray-400 mt-0.5">{(100 - usedPercent).toFixed(0)}% متبقٍ</p>
                      </div>
                      <Button
                        size="sm" variant="ghost"
                        onClick={() => toggleMutation.mutate(card.id)}
                        disabled={toggleMutation.isPending}
                        className={card.isActive ? "text-gray-500" : "text-green-600"}
                        data-testid={`button-toggle-${card.id}`}
                      >
                        {card.isActive ? <ToggleRight className="w-5 h-5" /> : <ToggleLeft className="w-5 h-5" />}
                      </Button>
                    </div>
                    {card.expiryDate && (
                      <p className="text-xs text-gray-400 mt-2">تنتهي: {new Date(card.expiryDate).toLocaleDateString("ar-SA")}</p>
                    )}
                  </CardContent>
                </Card>
              );
            })}
          </div>
        )}
      </div>

      <Dialog open={showCreate} onOpenChange={setShowCreate}>
        <DialogContent dir="rtl" className="max-w-sm">
          <DialogHeader><DialogTitle>إنشاء بطاقة هدية جديدة</DialogTitle></DialogHeader>
          <div className="space-y-3">
            <div>
              <Label>الرصيد الأولي (ر.س) *</Label>
              <Input type="number" min="1" value={form.initialBalance} onChange={e => setForm(f => ({ ...f, initialBalance: Number(e.target.value) }))} data-testid="input-balance" />
            </div>
            <div>
              <Label>تاريخ الانتهاء (اختياري)</Label>
              <Input type="date" value={form.expiryDate} onChange={e => setForm(f => ({ ...f, expiryDate: e.target.value }))} />
            </div>
            <div>
              <Label>اسم المستلم (اختياري)</Label>
              <Input value={form.recipientName} onChange={e => setForm(f => ({ ...f, recipientName: e.target.value }))} />
            </div>
            <div>
              <Label>هاتف المستلم (اختياري)</Label>
              <Input value={form.recipientPhone} onChange={e => setForm(f => ({ ...f, recipientPhone: e.target.value }))} />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreate(false)}>إلغاء</Button>
            <Button onClick={() => createMutation.mutate(form)} disabled={createMutation.isPending || !form.initialBalance} className="bg-[#6B3F2A] text-white" data-testid="button-confirm-create">
              {createMutation.isPending && <Loader2 className="w-4 h-4 animate-spin ml-2" />}
              إنشاء البطاقة
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Link } from "wouter";
import { ArrowRight, Plus, Trash2, DollarSign, TrendingDown, Loader2, Receipt } from "lucide-react";

interface Expense {
  id: string;
  category: string;
  description: string;
  amount: number;
  date: string;
  branchId: string;
  paymentMethod: string;
  notes: string;
  recordedBy: string;
}

const expenseCategories = [
  "مواد خام", "إيجار", "رواتب", "مرافق (كهرباء/ماء)", "صيانة", "تسويق وإعلان",
  "مواد تنظيف", "أدوات ومعدات", "نقل وشحن", "ضرائب ورسوم", "أخرى"
];

const paymentMethods: Record<string, string> = { cash: "نقداً", card: "بطاقة", bank_transfer: "تحويل بنكي", other: "أخرى" };

const today = new Date().toISOString().split("T")[0];
const monthAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split("T")[0];

const emptyForm = { category: "مواد خام", description: "", amount: 0, date: today, branchId: "", paymentMethod: "cash", notes: "" };

export default function AdminExpenses() {
  const { toast } = useToast();
  const [showDialog, setShowDialog] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [from, setFrom] = useState(monthAgo);
  const [to, setTo] = useState(today);
  const [catFilter, setCatFilter] = useState("all");

  const { data: expenses = [], isLoading } = useQuery<Expense[]>({
    queryKey: ["/api/admin/expenses", from, to, catFilter],
    queryFn: () => {
      const p = new URLSearchParams({ from, to });
      if (catFilter !== "all") p.set("category", catFilter);
      return fetch(`/api/admin/expenses?${p}`, { credentials: "include" }).then(r => r.json());
    },
  });

  const createMutation = useMutation({
    mutationFn: (d: typeof form) => apiRequest("POST", "/api/admin/expenses", d),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/expenses"] });
      setShowDialog(false); setForm(emptyForm);
      toast({ title: "تم تسجيل المصروف" });
    },
    onError: (e: any) => toast({ title: e.message || "خطأ", variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiRequest("DELETE", `/api/admin/expenses/${id}`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/admin/expenses"] }); toast({ title: "تم الحذف" }); },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const total = expenses.reduce((s, e) => s + e.amount, 0);
  const byCategory: Record<string, number> = {};
  expenses.forEach(e => { byCategory[e.category] = (byCategory[e.category] || 0) + e.amount; });
  const topCat = Object.entries(byCategory).sort((a, b) => b[1] - a[1]).slice(0, 5);

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-5xl mx-auto p-6 space-y-6">
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">المصروفات</h1>
              <p className="text-sm text-gray-500">تتبع وتحليل مصروفات الكافيه</p>
            </div>
          </div>
          <Button onClick={() => setShowDialog(true)} className="bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white" data-testid="button-add-expense">
            <Plus className="w-4 h-4 ml-1" /> تسجيل مصروف
          </Button>
        </div>

        {/* Summary */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <Card className="bg-white">
            <CardContent className="p-4">
              <div className="flex items-center gap-3">
                <div className="w-12 h-12 bg-red-50 rounded-xl flex items-center justify-center">
                  <TrendingDown className="w-6 h-6 text-red-500" />
                </div>
                <div>
                  <p className="text-3xl font-bold text-gray-900">{total.toFixed(2)}</p>
                  <p className="text-sm text-gray-500">إجمالي المصروفات (ر.س)</p>
                </div>
              </div>
            </CardContent>
          </Card>
          <Card className="bg-white">
            <CardHeader className="pb-2"><CardTitle className="text-sm text-gray-600">توزيع حسب الفئة</CardTitle></CardHeader>
            <CardContent className="space-y-2 pt-0">
              {topCat.map(([cat, amt]) => (
                <div key={cat} className="flex items-center justify-between">
                  <span className="text-sm text-gray-600 truncate max-w-[150px]">{cat}</span>
                  <div className="flex items-center gap-2">
                    <div className="w-20 h-1.5 bg-gray-200 rounded-full overflow-hidden">
                      <div className="h-full bg-[#6B3F2A] rounded-full" style={{ width: `${total > 0 ? (amt / total) * 100 : 0}%` }} />
                    </div>
                    <span className="text-xs font-mono text-gray-700 w-16 text-left">{amt.toFixed(0)} ر.س</span>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        </div>

        {/* Filters */}
        <div className="flex gap-3 flex-wrap">
          <Input type="date" value={from} onChange={e => setFrom(e.target.value)} className="w-40 bg-white" />
          <Input type="date" value={to} onChange={e => setTo(e.target.value)} className="w-40 bg-white" />
          <Select value={catFilter} onValueChange={setCatFilter}>
            <SelectTrigger className="w-48 bg-white"><SelectValue /></SelectTrigger>
            <SelectContent>
              <SelectItem value="all">كل الفئات</SelectItem>
              {expenseCategories.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}
            </SelectContent>
          </Select>
        </div>

        {/* Table */}
        <Card className="bg-white">
          <CardContent className="p-0">
            {isLoading ? (
              <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
            ) : expenses.length === 0 ? (
              <div className="text-center py-12 text-gray-400">
                <Receipt className="w-12 h-12 mx-auto mb-3 opacity-30" />
                <p>لا توجد مصروفات في هذه الفترة</p>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead className="bg-gray-50">
                    <tr className="text-right">
                      <th className="py-3 px-4 text-gray-500 font-medium">التاريخ</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">الفئة</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">الوصف</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">المبلغ</th>
                      <th className="py-3 px-4 text-gray-500 font-medium">طريقة الدفع</th>
                      <th className="py-3 px-4"></th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-50">
                    {expenses.map(e => (
                      <tr key={e.id} className="hover:bg-gray-50" data-testid={`row-expense-${e.id}`}>
                        <td className="py-3 px-4 text-gray-600 font-mono text-xs">{new Date(e.date).toLocaleDateString("ar-SA")}</td>
                        <td className="py-3 px-4"><Badge className="bg-gray-100 text-gray-700 border-0 text-xs">{e.category}</Badge></td>
                        <td className="py-3 px-4 text-gray-700">{e.description}</td>
                        <td className="py-3 px-4 font-bold text-red-600">{e.amount.toFixed(2)} ر.س</td>
                        <td className="py-3 px-4 text-gray-500 text-xs">{paymentMethods[e.paymentMethod] || e.paymentMethod}</td>
                        <td className="py-3 px-4">
                          <Button size="icon" variant="ghost" className="h-7 w-7 text-red-400 hover:text-red-600" onClick={() => confirm("حذف هذا المصروف؟") && deleteMutation.mutate(e.id)} data-testid={`button-delete-${e.id}`}>
                            <Trash2 className="w-3.5 h-3.5" />
                          </Button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                  <tfoot className="bg-gray-50">
                    <tr>
                      <td colSpan={3} className="py-3 px-4 font-bold text-gray-700 text-left">الإجمالي</td>
                      <td className="py-3 px-4 font-bold text-red-600 text-lg">{total.toFixed(2)} ر.س</td>
                      <td colSpan={2}></td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      <Dialog open={showDialog} onOpenChange={setShowDialog}>
        <DialogContent dir="rtl" className="max-w-sm">
          <DialogHeader><DialogTitle>تسجيل مصروف جديد</DialogTitle></DialogHeader>
          <div className="space-y-3">
            <div>
              <Label>الفئة *</Label>
              <Select value={form.category} onValueChange={v => setForm(f => ({ ...f, category: v }))}>
                <SelectTrigger data-testid="select-category"><SelectValue /></SelectTrigger>
                <SelectContent>{expenseCategories.map(c => <SelectItem key={c} value={c}>{c}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>الوصف *</Label>
              <Input value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} placeholder="وصف المصروف..." data-testid="input-description" />
            </div>
            <div className="grid grid-cols-2 gap-3">
              <div>
                <Label>المبلغ (ر.س) *</Label>
                <Input type="number" min="0" step="0.01" value={form.amount} onChange={e => setForm(f => ({ ...f, amount: Number(e.target.value) }))} data-testid="input-amount" />
              </div>
              <div>
                <Label>التاريخ</Label>
                <Input type="date" value={form.date} onChange={e => setForm(f => ({ ...f, date: e.target.value }))} />
              </div>
            </div>
            <div>
              <Label>طريقة الدفع</Label>
              <Select value={form.paymentMethod} onValueChange={v => setForm(f => ({ ...f, paymentMethod: v }))}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  {Object.entries(paymentMethods).map(([k, v]) => <SelectItem key={k} value={k}>{v}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label>ملاحظات</Label>
              <Textarea value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} className="h-16 resize-none" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowDialog(false)}>إلغاء</Button>
            <Button onClick={() => createMutation.mutate(form)} disabled={createMutation.isPending || !form.description || !form.amount} className="bg-[#6B3F2A] text-white" data-testid="button-save-expense">
              {createMutation.isPending && <Loader2 className="w-4 h-4 animate-spin ml-2" />}
              تسجيل
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Textarea } from "@/components/ui/textarea";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Link } from "wouter";
import {
  ArrowRight, Calendar, Users, Clock, Phone, CheckCircle2, XCircle,
  Plus, Search, Loader2, CalendarDays, Edit,
} from "lucide-react";

interface TableReservation {
  id: string;
  customerName: string;
  customerPhone: string;
  date: string;
  time: string;
  partySize: number;
  tableNumber?: string;
  branchId?: string;
  status: "pending" | "confirmed" | "cancelled" | "completed" | "no_show";
  notes?: string;
  confirmedBy?: string;
  createdAt: string;
}

const statusConfig: Record<string, { label: string; color: string }> = {
  pending:   { label: "قيد الانتظار", color: "bg-amber-100 text-amber-700" },
  confirmed: { label: "مؤكد",         color: "bg-green-100 text-green-700" },
  cancelled: { label: "ملغي",          color: "bg-red-100 text-red-700" },
  completed: { label: "مكتمل",        color: "bg-blue-100 text-blue-700" },
  no_show:   { label: "لم يحضر",      color: "bg-gray-100 text-gray-600" },
};

const today = new Date().toISOString().split("T")[0];
const emptyForm = { customerName: "", customerPhone: "", date: today, time: "12:00", partySize: 2, tableNumber: "", notes: "" };

export default function AdminTableReservations() {
  const { toast } = useToast();
  const [statusFilter, setStatusFilter] = useState("all");
  const [dateFilter, setDateFilter] = useState(today);
  const [showCreate, setShowCreate] = useState(false);
  const [editItem, setEditItem] = useState<TableReservation | null>(null);
  const [form, setForm] = useState(emptyForm);

  const { data: reservations = [], isLoading } = useQuery<TableReservation[]>({
    queryKey: ["/api/admin/table-reservations", statusFilter, dateFilter],
    queryFn: () => {
      const p = new URLSearchParams();
      if (statusFilter !== "all") p.set("status", statusFilter);
      if (dateFilter) p.set("date", dateFilter);
      return fetch(`/api/admin/table-reservations?${p}`, { credentials: "include" }).then(r => r.json());
    },
    refetchInterval: 60000,
  });

  const createMutation = useMutation({
    mutationFn: (d: typeof form) => fetch("/api/table-reservations", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      credentials: "include",
      body: JSON.stringify(d),
    }).then(r => r.json()),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/table-reservations"] });
      setShowCreate(false); setForm(emptyForm);
      toast({ title: "تم إنشاء الحجز بنجاح" });
    },
    onError: () => toast({ title: "خطأ في إنشاء الحجز", variant: "destructive" }),
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: any }) => apiRequest("PATCH", `/api/admin/table-reservations/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/table-reservations"] });
      setEditItem(null);
      toast({ title: "تم التحديث" });
    },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiRequest("DELETE", `/api/admin/table-reservations/${id}`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/admin/table-reservations"] }); toast({ title: "تم الحذف" }); },
  });

  const setStatus = (id: string, status: string) => updateMutation.mutate({ id, data: { status } });
  const pendingCount = reservations.filter(r => r.status === "pending").length;

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-5xl mx-auto p-6 space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
                حجوزات الطاولات
                {pendingCount > 0 && <Badge className="bg-amber-500 text-white">{pendingCount} معلّق</Badge>}
              </h1>
              <p className="text-sm text-gray-500">إدارة حجوزات قاعة الكافيه</p>
            </div>
          </div>
          <Button onClick={() => { setForm(emptyForm); setShowCreate(true); }} className="bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white" data-testid="button-add-reservation">
            <Plus className="w-4 h-4 ml-1" /> حجز جديد
          </Button>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-5 gap-3">
          {Object.entries(statusConfig).map(([k, v]) => {
            const count = reservations.filter(r => r.status === k).length;
            return (
              <button key={k} onClick={() => setStatusFilter(statusFilter === k ? "all" : k)}
                className={`p-3 rounded-xl text-center transition-all border-2 ${statusFilter === k ? "border-[#6B3F2A] bg-[#6B3F2A]/5" : "border-transparent bg-white hover:border-gray-200"}`}
                data-testid={`filter-${k}`}>
                <p className={`text-xl font-bold ${statusFilter === k ? "text-[#6B3F2A]" : "text-gray-800"}`}>{count}</p>
                <p className="text-xs text-gray-500 mt-0.5">{v.label}</p>
              </button>
            );
          })}
        </div>

        {/* Date filter */}
        <div className="flex gap-3">
          <Input type="date" value={dateFilter} onChange={e => setDateFilter(e.target.value)} className="w-48 bg-white" />
          <Button variant="outline" onClick={() => setDateFilter("")} className="text-gray-500">كل التواريخ</Button>
        </div>

        {/* Reservations */}
        {isLoading ? (
          <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
        ) : reservations.length === 0 ? (
          <div className="text-center py-12 text-gray-400">
            <CalendarDays className="w-12 h-12 mx-auto mb-3 opacity-30" />
            <p>لا توجد حجوزات</p>
          </div>
        ) : (
          <div className="space-y-3">
            {reservations.map(r => (
              <Card key={r.id} className="bg-white" data-testid={`card-reservation-${r.id}`}>
                <CardContent className="p-4">
                  <div className="flex items-start justify-between gap-3">
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <p className="font-bold text-gray-900">{r.customerName}</p>
                        <Badge className={`${statusConfig[r.status]?.color} border-0 text-xs`}>{statusConfig[r.status]?.label}</Badge>
                        {r.tableNumber && <Badge variant="outline" className="text-xs">طاولة {r.tableNumber}</Badge>}
                      </div>
                      <div className="flex flex-wrap gap-3 text-sm text-gray-600">
                        <span className="flex items-center gap-1"><Phone className="w-3.5 h-3.5" /> {r.customerPhone}</span>
                        <span className="flex items-center gap-1"><Calendar className="w-3.5 h-3.5" /> {new Date(r.date).toLocaleDateString("ar-SA")}</span>
                        <span className="flex items-center gap-1"><Clock className="w-3.5 h-3.5" /> {r.time}</span>
                        <span className="flex items-center gap-1"><Users className="w-3.5 h-3.5" /> {r.partySize} أشخاص</span>
                      </div>
                      {r.notes && <p className="text-xs text-gray-400 mt-1">{r.notes}</p>}
                    </div>
                    <div className="flex flex-col gap-1 shrink-0">
                      {r.status === "pending" && (
                        <>
                          <Button size="sm" className="bg-green-600 hover:bg-green-700 text-white h-7 text-xs" onClick={() => setStatus(r.id, "confirmed")} data-testid={`button-confirm-${r.id}`}>
                            <CheckCircle2 className="w-3.5 h-3.5 ml-1" /> تأكيد
                          </Button>
                          <Button size="sm" variant="outline" className="border-red-200 text-red-600 h-7 text-xs" onClick={() => setStatus(r.id, "cancelled")} data-testid={`button-cancel-${r.id}`}>
                            <XCircle className="w-3.5 h-3.5 ml-1" /> إلغاء
                          </Button>
                        </>
                      )}
                      {r.status === "confirmed" && (
                        <>
                          <Button size="sm" className="bg-blue-600 hover:bg-blue-700 text-white h-7 text-xs" onClick={() => setStatus(r.id, "completed")} data-testid={`button-complete-${r.id}`}>مكتمل</Button>
                          <Button size="sm" variant="outline" className="border-gray-200 text-gray-600 h-7 text-xs" onClick={() => setStatus(r.id, "no_show")} data-testid={`button-noshow-${r.id}`}>لم يحضر</Button>
                        </>
                      )}
                      <Button size="sm" variant="ghost" className="h-7 text-xs text-red-400" onClick={() => confirm("حذف هذا الحجز؟") && deleteMutation.mutate(r.id)} data-testid={`button-delete-${r.id}`}>
                        حذف
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      {/* Create Dialog */}
      <Dialog open={showCreate} onOpenChange={setShowCreate}>
        <DialogContent dir="rtl" className="max-w-md">
          <DialogHeader><DialogTitle>حجز جديد</DialogTitle></DialogHeader>
          <div className="grid grid-cols-2 gap-3">
            <div className="col-span-2"><Label>اسم العميل *</Label><Input value={form.customerName} onChange={e => setForm(f => ({ ...f, customerName: e.target.value }))} data-testid="input-customer-name" /></div>
            <div className="col-span-2"><Label>رقم الهاتف *</Label><Input value={form.customerPhone} onChange={e => setForm(f => ({ ...f, customerPhone: e.target.value }))} data-testid="input-customer-phone" /></div>
            <div><Label>تاريخ الحجز *</Label><Input type="date" value={form.date} onChange={e => setForm(f => ({ ...f, date: e.target.value }))} /></div>
            <div><Label>الوقت *</Label><Input type="time" value={form.time} onChange={e => setForm(f => ({ ...f, time: e.target.value }))} /></div>
            <div><Label>عدد الأشخاص</Label><Input type="number" min="1" max="20" value={form.partySize} onChange={e => setForm(f => ({ ...f, partySize: Number(e.target.value) }))} /></div>
            <div><Label>رقم الطاولة</Label><Input value={form.tableNumber} onChange={e => setForm(f => ({ ...f, tableNumber: e.target.value }))} placeholder="اختياري" /></div>
            <div className="col-span-2"><Label>ملاحظات</Label><Textarea value={form.notes} onChange={e => setForm(f => ({ ...f, notes: e.target.value }))} className="h-20 resize-none" /></div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreate(false)}>إلغاء</Button>
            <Button onClick={() => createMutation.mutate(form)} disabled={createMutation.isPending || !form.customerName || !form.customerPhone} className="bg-[#6B3F2A] text-white" data-testid="button-save-reservation">
              {createMutation.isPending && <Loader2 className="w-4 h-4 animate-spin ml-2" />}
              إنشاء الحجز
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Link } from "wouter";
import {
  ArrowRight, TrendingUp, TrendingDown, ShoppingCart, DollarSign,
  BarChart3, Clock, Award, RefreshCw, Package, CreditCard,
} from "lucide-react";

interface AnalyticsData {
  totalRevenue: number;
  totalOrders: number;
  avgOrderValue: number;
  totalExpenses: number;
  netProfit: number;
  topProducts: { productId: string; name: string; qty: number; revenue: number }[];
  dailyRevenue: Record<string, number>;
  paymentBreakdown: Record<string, number>;
  typeBreakdown: Record<string, number>;
  period: string;
}

interface HourlyData {
  [hour: number]: { count: number; revenue: number };
}

const periods = [
  { key: "today", label: "اليوم" },
  { key: "week", label: "أسبوع" },
  { key: "month", label: "شهر" },
  { key: "year", label: "سنة" },
];

const paymentLabels: Record<string, string> = {
  cash: "نقداً", card: "بطاقة", apple_pay: "Apple Pay",
  bank_transfer: "تحويل", tamara: "تمارا", tabby: "تابي",
  stc_pay: "STC Pay", other: "أخرى",
};

const typeLabels: Record<string, string> = {
  delivery: "توصيل", pickup: "استلام", dine_in: "داخلي",
  car_pickup: "سيارة", other: "أخرى",
};

function formatNum(n: number) {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + "م";
  if (n >= 1000) return (n / 1000).toFixed(1) + "ك";
  return n.toFixed(0);
}

export default function AdminAnalytics() {
  const [period, setPeriod] = useState("month");

  const { data: analytics, isLoading, refetch } = useQuery<AnalyticsData>({
    queryKey: ["/api/admin/analytics/overview", period],
    queryFn: () => fetch(`/api/admin/analytics/overview?period=${period}`, { credentials: "include" }).then(r => r.json()),
  });

  const { data: hourly } = useQuery<HourlyData>({
    queryKey: ["/api/admin/analytics/hourly"],
  });

  const dailyEntries = analytics ? Object.entries(analytics.dailyRevenue).sort((a, b) => a[0].localeCompare(b[0])) : [];
  const maxDaily = dailyEntries.length > 0 ? Math.max(...dailyEntries.map(([, v]) => v)) : 1;

  const hourlyEntries = hourly ? Object.entries(hourly).map(([h, d]) => ({ hour: Number(h), ...d })) : [];
  const maxHourly = hourlyEntries.length > 0 ? Math.max(...hourlyEntries.map(e => e.count)) : 1;

  const paymentEntries = analytics ? Object.entries(analytics.paymentBreakdown).sort((a, b) => b[1] - a[1]) : [];
  const totalPay = paymentEntries.reduce((s, [, v]) => s + v, 0);

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-6xl mx-auto p-6 space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">التحليلات المتقدمة</h1>
              <p className="text-sm text-gray-500">تحليل عميق لأداء الكافيه</p>
            </div>
          </div>
          <Button variant="outline" size="sm" onClick={() => refetch()}>
            <RefreshCw className="w-4 h-4 ml-1" /> تحديث
          </Button>
        </div>

        {/* Period selector */}
        <div className="flex gap-2">
          {periods.map(p => (
            <Button key={p.key} size="sm" variant={period === p.key ? "default" : "outline"}
              onClick={() => setPeriod(p.key)}
              className={period === p.key ? "bg-[#6B3F2A] text-white" : ""}
              data-testid={`period-${p.key}`}>
              {p.label}
            </Button>
          ))}
        </div>

        {isLoading ? (
          <div className="text-center py-16 text-gray-400">جاري تحميل التحليلات...</div>
        ) : analytics ? (
          <>
            {/* KPI cards */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              {[
                { label: "إجمالي المبيعات", value: `${formatNum(analytics.totalRevenue)} ر.س`, icon: DollarSign, color: "text-green-600 bg-green-50", trend: analytics.totalRevenue > 0 ? "up" : "flat" },
                { label: "عدد الطلبات", value: analytics.totalOrders.toString(), icon: ShoppingCart, color: "text-blue-600 bg-blue-50", trend: "up" },
                { label: "متوسط قيمة الطلب", value: `${analytics.avgOrderValue.toFixed(1)} ر.س`, icon: BarChart3, color: "text-purple-600 bg-purple-50", trend: "flat" },
                { label: "صافي الربح", value: `${formatNum(analytics.netProfit)} ر.س`, icon: TrendingUp, color: analytics.netProfit >= 0 ? "text-emerald-600 bg-emerald-50" : "text-red-600 bg-red-50", trend: analytics.netProfit >= 0 ? "up" : "down" },
              ].map(card => (
                <Card key={card.label} className="bg-white">
                  <CardContent className="p-4">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-3 ${card.color}`}>
                      <card.icon className="w-5 h-5" />
                    </div>
                    <p className="text-2xl font-bold text-gray-900">{card.value}</p>
                    <p className="text-xs text-gray-500 mt-1">{card.label}</p>
                  </CardContent>
                </Card>
              ))}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Daily Revenue Chart */}
              <Card className="bg-white">
                <CardHeader className="pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <BarChart3 className="w-5 h-5 text-[#6B3F2A]" /> المبيعات اليومية (آخر 7 أيام)
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="flex items-end gap-2 h-32">
                    {dailyEntries.map(([date, val]) => {
                      const heightPct = maxDaily > 0 ? (val / maxDaily) * 100 : 0;
                      const dayLabel = new Date(date).toLocaleDateString("ar-SA", { weekday: "short" });
                      return (
                        <div key={date} className="flex-1 flex flex-col items-center gap-1">
                          <span className="text-[9px] text-gray-400 font-mono">{val > 0 ? formatNum(val) : ""}</span>
                          <div className="w-full relative" style={{ height: "80px" }}>
                            <div className="absolute bottom-0 left-0 right-0 bg-[#6B3F2A]/80 rounded-t-md transition-all"
                              style={{ height: `${Math.max(heightPct, val > 0 ? 5 : 0)}%` }} />
                          </div>
                          <span className="text-[9px] text-gray-400">{dayLabel}</span>
                        </div>
                      );
                    })}
                  </div>
                </CardContent>
              </Card>

              {/* Top Products */}
              <Card className="bg-white">
                <CardHeader className="pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <Award className="w-5 h-5 text-[#6B3F2A]" /> أكثر المنتجات مبيعاً
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-2">
                    {analytics.topProducts.length === 0 ? (
                      <p className="text-center text-gray-400 py-4 text-sm">لا توجد بيانات</p>
                    ) : analytics.topProducts.map((p, i) => (
                      <div key={p.productId} className="flex items-center gap-3">
                        <span className={`w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold ${i === 0 ? "bg-amber-100 text-amber-700" : i === 1 ? "bg-gray-100 text-gray-600" : i === 2 ? "bg-orange-100 text-orange-600" : "bg-gray-50 text-gray-500"}`}>{i + 1}</span>
                        <span className="flex-1 text-sm text-gray-700 truncate">{p.name || "منتج"}</span>
                        <span className="text-sm font-bold text-gray-900">{p.qty}</span>
                        <span className="text-xs text-gray-400 w-16 text-left">{p.revenue.toFixed(0)} ر.س</span>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>

              {/* Payment breakdown */}
              <Card className="bg-white">
                <CardHeader className="pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <CreditCard className="w-5 h-5 text-[#6B3F2A]" /> توزيع طرق الدفع
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-2">
                    {paymentEntries.length === 0 ? (
                      <p className="text-center text-gray-400 py-4 text-sm">لا توجد بيانات</p>
                    ) : paymentEntries.map(([method, count]) => {
                      const pct = totalPay > 0 ? (count / totalPay) * 100 : 0;
                      return (
                        <div key={method} className="flex items-center gap-3">
                          <span className="text-sm text-gray-600 w-24 truncate">{paymentLabels[method] || method}</span>
                          <div className="flex-1 h-2 bg-gray-100 rounded-full overflow-hidden">
                            <div className="h-full bg-[#6B3F2A] rounded-full" style={{ width: `${pct}%` }} />
                          </div>
                          <span className="text-sm font-bold text-gray-700 w-8 text-left">{count}</span>
                          <span className="text-xs text-gray-400 w-10 text-left">{pct.toFixed(0)}%</span>
                        </div>
                      );
                    })}
                  </div>
                </CardContent>
              </Card>

              {/* Hourly breakdown */}
              <Card className="bg-white">
                <CardHeader className="pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <Clock className="w-5 h-5 text-[#6B3F2A]" /> توزيع الطلبات بالساعة (اليوم)
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="flex items-end gap-0.5 h-24">
                    {hourlyEntries.map(e => {
                      const heightPct = maxHourly > 0 ? (e.count / maxHourly) * 100 : 0;
                      const isPeak = e.count === Math.max(...hourlyEntries.map(x => x.count)) && e.count > 0;
                      return (
                        <div key={e.hour} className="flex-1 flex flex-col items-center" title={`${e.hour}:00 — ${e.count} طلب`}>
                          <div className="w-full" style={{ height: "70px" }}>
                            <div className="w-full" style={{ height: `${100 - heightPct}%` }} />
                            <div className={`w-full rounded-t-sm ${isPeak ? "bg-amber-400" : "bg-[#6B3F2A]/60"}`}
                              style={{ height: `${Math.max(heightPct, e.count > 0 ? 5 : 0)}%` }} />
                          </div>
                          {e.hour % 4 === 0 && <span className="text-[7px] text-gray-400">{e.hour}</span>}
                        </div>
                      );
                    })}
                  </div>
                  <p className="text-xs text-gray-400 text-center mt-2">ساعات اليوم (0 — 23)</p>
                </CardContent>
              </Card>
            </div>

            {/* Revenue vs Expenses */}
            <Card className="bg-white">
              <CardHeader className="pb-3">
                <CardTitle className="text-base">ملخص مالي</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-3 gap-4 text-center">
                  <div className="p-4 bg-green-50 rounded-xl">
                    <p className="text-xs text-gray-500 mb-1">إجمالي المبيعات</p>
                    <p className="text-2xl font-bold text-green-700">{analytics.totalRevenue.toFixed(2)}</p>
                    <p className="text-xs text-gray-400">ر.س</p>
                  </div>
                  <div className="p-4 bg-red-50 rounded-xl">
                    <p className="text-xs text-gray-500 mb-1">إجمالي المصروفات</p>
                    <p className="text-2xl font-bold text-red-600">{analytics.totalExpenses.toFixed(2)}</p>
                    <p className="text-xs text-gray-400">ر.س</p>
                  </div>
                  <div className={`p-4 rounded-xl ${analytics.netProfit >= 0 ? "bg-emerald-50" : "bg-orange-50"}`}>
                    <p className="text-xs text-gray-500 mb-1">صافي الربح</p>
                    <p className={`text-2xl font-bold ${analytics.netProfit >= 0 ? "text-emerald-700" : "text-orange-600"}`}>{analytics.netProfit.toFixed(2)}</p>
                    <p className="text-xs text-gray-400">ر.س</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </>
        ) : null}
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { useQuery } from "@tanstack/react-query";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  ShoppingCart, Plus, Minus, X, ChevronRight, CheckCircle2,
  Coffee, Search, Loader2, ArrowRight,
} from "lucide-react";
import { Link } from "wouter";
import logoDarkImg from "/logo-dark.png";

interface Product {
  id: string;
  name: string;
  nameAr?: string;
  nameEn?: string;
  price: number;
  image?: string;
  category?: string;
  description?: string;
  variants?: any[];
  isAvailable?: boolean;
  isActive?: boolean;
}

interface CartItem {
  product: Product;
  quantity: number;
  variant?: any;
  notes: string;
  price: number;
}

interface Category {
  id: string;
  name: string;
  nameAr?: string;
}

export default function Kiosk() {
  const { toast } = useToast();
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCat, setSelectedCat] = useState<string>("all");
  const [search, setSearch] = useState("");
  const [showCart, setShowCart] = useState(false);
  const [showCheckout, setShowCheckout] = useState(false);
  const [orderPlaced, setOrderPlaced] = useState(false);
  const [isPlacing, setIsPlacing] = useState(false);
  const [customerName, setCustomerName] = useState("");
  const [tableNumber, setTableNumber] = useState("");
  const [paymentMethod, setPaymentMethod] = useState("cash");
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [idleTimer, setIdleTimer] = useState(0);

  // Idle reset (3 min)
  useEffect(() => {
    const reset = () => setIdleTimer(0);
    const events = ["click", "touchstart", "mousemove", "keydown"];
    events.forEach(e => document.addEventListener(e, reset));
    const interval = setInterval(() => {
      setIdleTimer(prev => {
        if (prev >= 180) {
          setCart([]); setShowCart(false); setShowCheckout(false);
          setCustomerName(""); setTableNumber(""); setSearch("");
          return 0;
        }
        return prev + 1;
      });
    }, 1000);
    return () => { events.forEach(e => document.removeEventListener(e, reset)); clearInterval(interval); };
  }, []);

  const { data: products = [] } = useQuery<Product[]>({ queryKey: ["/api/products"] });
  const { data: categories = [] } = useQuery<Category[]>({ queryKey: ["/api/categories"] });

  const activeProducts = (products as Product[]).filter(p => p.isActive !== false && p.isAvailable !== false);
  const filtered = activeProducts.filter(p => {
    if (selectedCat !== "all" && p.category !== selectedCat) return false;
    const name = p.nameAr || p.name || "";
    if (search && !name.includes(search)) return false;
    return true;
  });

  const cartTotal = cart.reduce((s, item) => s + item.price * item.quantity, 0);
  const cartCount = cart.reduce((s, item) => s + item.quantity, 0);

  function addToCart(product: Product, variant?: any) {
    const price = variant?.price || product.price || 0;
    setCart(prev => {
      const key = product.id + (variant?.id || "");
      const existing = prev.find(i => i.product.id + (i.variant?.id || "") === key);
      if (existing) return prev.map(i => i.product.id + (i.variant?.id || "") === key ? { ...i, quantity: i.quantity + 1 } : i);
      return [...prev, { product, quantity: 1, variant, notes: "", price }];
    });
    setSelectedProduct(null);
    toast({ title: `✅ تمت الإضافة — ${product.nameAr || product.name}`, });
  }

  function updateQty(idx: number, delta: number) {
    setCart(prev => {
      const updated = [...prev];
      updated[idx] = { ...updated[idx], quantity: updated[idx].quantity + delta };
      return updated.filter(i => i.quantity > 0);
    });
  }

  function removeItem(idx: number) { setCart(prev => prev.filter((_, i) => i !== idx)); }

  async function placeOrder() {
    if (cart.length === 0) return;
    setIsPlacing(true);
    try {
      const orderData = {
        items: cart.map(i => ({
          productId: i.product.id,
          title: i.product.nameAr || i.product.name,
          quantity: i.quantity,
          price: i.price,
          variant: i.variant || null,
          notes: i.notes,
        })),
        total: cartTotal.toFixed(2),
        subtotal: cartTotal.toFixed(2),
        shippingCost: "0",
        paymentMethod,
        shippingMethod: "dine_in",
        orderType: "dine_in",
        customerName: customerName || "زبون كشك",
        tableNumber: tableNumber || "",
        notes: `طلب كشك — طاولة ${tableNumber || "غير محددة"}`,
        status: "new",
        paymentStatus: paymentMethod === "cash" ? "pending" : "paid",
      };

      const r = await fetch("/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(orderData),
      });

      if (r.ok) {
        setOrderPlaced(true);
        setCart([]);
        setTimeout(() => {
          setOrderPlaced(false); setShowCheckout(false);
          setCustomerName(""); setTableNumber("");
        }, 5000);
      } else {
        toast({ title: "خطأ في إرسال الطلب", variant: "destructive" });
      }
    } catch {
      toast({ title: "خطأ في الاتصال", variant: "destructive" });
    }
    setIsPlacing(false);
  }

  const catName = (id: string) => {
    const cat = (categories as Category[]).find(c => c.id === id);
    return cat?.nameAr || cat?.name || id;
  };

  return (
    <div className="min-h-screen bg-[#1a1108] text-white overflow-hidden select-none" dir="rtl">
      {/* Header */}
      <div className="flex items-center justify-between px-6 py-4 bg-[#6B3F2A] shadow-lg">
        <div className="flex items-center gap-3">
          <img src={logoDarkImg} alt="فوجي كافيه" className="w-10 h-10 rounded-xl object-cover" onError={e => { (e.target as HTMLImageElement).src = "data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 40 40'%3E%3Crect width='40' height='40' rx='8' fill='%236B3F2A'/%3E%3C/svg%3E" }} />
          <div>
            <p className="font-black text-xl text-white">فوجي كافيه</p>
            <p className="text-white/60 text-xs">اطلب بنفسك</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <Link href="/admin"><Button variant="ghost" size="sm" className="text-white/60 hover:text-white text-xs"><ArrowRight className="w-3 h-3 ml-1" /> لوحة التحكم</Button></Link>
          <button onClick={() => setShowCart(true)} className="relative bg-white/10 hover:bg-white/20 rounded-xl p-3 transition-all" data-testid="button-cart">
            <ShoppingCart className="w-6 h-6" />
            {cartCount > 0 && (
              <span className="absolute -top-1 -left-1 bg-[#E8637A] text-white text-xs font-bold w-5 h-5 rounded-full flex items-center justify-center animate-bounce">
                {cartCount}
              </span>
            )}
          </button>
        </div>
      </div>

      <div className="flex gap-0 h-[calc(100vh-72px)]">
        {/* Category sidebar */}
        <div className="w-28 bg-[#251508] flex flex-col overflow-y-auto no-scrollbar py-3">
          <button
            onClick={() => setSelectedCat("all")}
            className={`py-4 px-2 text-center text-xs font-bold transition-all border-r-4 ${selectedCat === "all" ? "text-[#E8637A] border-[#E8637A] bg-[#E8637A]/10" : "text-white/50 border-transparent hover:text-white/80"}`}
            data-testid="cat-all"
          >
            <Coffee className="w-5 h-5 mx-auto mb-1" />
            الكل
          </button>
          {(categories as Category[]).map(cat => (
            <button
              key={cat.id}
              onClick={() => setSelectedCat(cat.id)}
              className={`py-4 px-2 text-center text-xs font-bold transition-all border-r-4 ${selectedCat === cat.id ? "text-[#E8637A] border-[#E8637A] bg-[#E8637A]/10" : "text-white/50 border-transparent hover:text-white/80"}`}
              data-testid={`cat-${cat.id}`}
            >
              {cat.nameAr || cat.name}
            </button>
          ))}
        </div>

        {/* Products grid */}
        <div className="flex-1 overflow-y-auto p-4">
          {/* Search */}
          <div className="relative mb-4">
            <Search className="absolute right-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/40" />
            <input
              value={search} onChange={e => setSearch(e.target.value)}
              placeholder="ابحث عن منتج..."
              className="w-full bg-white/10 text-white placeholder-white/40 rounded-xl pr-9 p-3 text-sm border border-white/10 focus:outline-none focus:border-[#E8637A]/50"
              data-testid="input-search"
            />
          </div>

          <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
            {filtered.map(product => {
              const name = product.nameAr || product.name;
              const inCart = cart.find(i => i.product.id === product.id);
              return (
                <button
                  key={product.id}
                  onClick={() => product.variants && product.variants.length > 0 ? setSelectedProduct(product) : addToCart(product)}
                  className="bg-white/5 hover:bg-white/10 border border-white/10 hover:border-[#E8637A]/40 rounded-2xl overflow-hidden transition-all text-right group active:scale-95"
                  data-testid={`product-${product.id}`}
                >
                  <div className="aspect-square bg-white/5 relative overflow-hidden">
                    {product.image ? (
                      <img src={product.image} alt={name} className="w-full h-full object-cover group-hover:scale-105 transition-transform" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                        <Coffee className="w-10 h-10 text-white/20" />
                      </div>
                    )}
                    {inCart && (
                      <div className="absolute top-2 left-2 bg-[#E8637A] text-white text-xs font-bold w-6 h-6 rounded-full flex items-center justify-center">
                        {inCart.quantity}
                      </div>
                    )}
                  </div>
                  <div className="p-3">
                    <p className="text-sm font-bold text-white mb-1 leading-tight">{name}</p>
                    <div className="flex items-center justify-between">
                      <p className="text-[#E8637A] font-black text-sm">{product.price} ر.س</p>
                      <div className="w-6 h-6 rounded-full bg-[#E8637A] flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all">
                        <Plus className="w-4 h-4 text-white" />
                      </div>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>

          {filtered.length === 0 && (
            <div className="text-center py-16 text-white/30">
              <Coffee className="w-16 h-16 mx-auto mb-3 opacity-30" />
              <p>لا توجد منتجات</p>
            </div>
          )}
        </div>
      </div>

      {/* Cart overlay */}
      {showCart && (
        <div className="fixed inset-0 z-50 flex" dir="rtl">
          <div className="flex-1 bg-black/70 backdrop-blur-sm" onClick={() => setShowCart(false)} />
          <div className="w-full max-w-sm bg-[#1a1108] flex flex-col shadow-2xl border-r border-white/10">
            <div className="flex items-center justify-between p-4 border-b border-white/10">
              <h2 className="text-lg font-bold text-white flex items-center gap-2">
                <ShoppingCart className="w-5 h-5" /> السلة ({cartCount})
              </h2>
              <Button variant="ghost" size="icon" onClick={() => setShowCart(false)} className="text-white/60"><X className="w-5 h-5" /></Button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-3">
              {cart.length === 0 ? (
                <p className="text-center text-white/40 py-12">السلة فارغة</p>
              ) : cart.map((item, idx) => (
                <div key={idx} className="bg-white/5 rounded-xl p-3 flex items-center gap-3" data-testid={`cart-item-${idx}`}>
                  <div className="flex-1">
                    <p className="text-sm font-bold text-white">{item.product.nameAr || item.product.name}</p>
                    {item.variant && <p className="text-xs text-white/50">{item.variant.nameAr || item.variant.name}</p>}
                    <p className="text-[#E8637A] text-sm font-bold mt-0.5">{(item.price * item.quantity).toFixed(2)} ر.س</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <button onClick={() => updateQty(idx, -1)} className="w-7 h-7 bg-white/10 rounded-full flex items-center justify-center hover:bg-white/20 text-white" data-testid={`button-decrease-${idx}`}><Minus className="w-3.5 h-3.5" /></button>
                    <span className="w-5 text-center text-sm font-bold text-white">{item.quantity}</span>
                    <button onClick={() => updateQty(idx, 1)} className="w-7 h-7 bg-[#E8637A] rounded-full flex items-center justify-center hover:bg-[#E8637A]/80 text-white" data-testid={`button-increase-${idx}`}><Plus className="w-3.5 h-3.5" /></button>
                    <button onClick={() => removeItem(idx)} className="w-7 h-7 bg-red-500/20 rounded-full flex items-center justify-center hover:bg-red-500/40 text-red-400" data-testid={`button-remove-${idx}`}><X className="w-3.5 h-3.5" /></button>
                  </div>
                </div>
              ))}
            </div>

            {cart.length > 0 && (
              <div className="p-4 border-t border-white/10 space-y-3">
                <div className="flex justify-between items-center text-white">
                  <span className="font-bold">الإجمالي</span>
                  <span className="text-2xl font-black text-[#E8637A]">{cartTotal.toFixed(2)} ر.س</span>
                </div>
                <Button onClick={() => { setShowCart(false); setShowCheckout(true); }} className="w-full h-12 bg-[#E8637A] hover:bg-[#E8637A]/90 text-white font-bold rounded-xl" data-testid="button-checkout">
                  إتمام الطلب <ChevronRight className="w-4 h-4 mr-1" />
                </Button>
                <Button onClick={() => setCart([])} variant="ghost" className="w-full text-white/50 hover:text-white/80 text-xs">مسح السلة</Button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Checkout Dialog */}
      <Dialog open={showCheckout} onOpenChange={setShowCheckout}>
        <DialogContent dir="rtl" className="max-w-sm bg-[#1a1108] text-white border border-white/10">
          {orderPlaced ? (
            <div className="text-center py-8">
              <CheckCircle2 className="w-16 h-16 text-green-400 mx-auto mb-4" />
              <h2 className="text-2xl font-bold text-white mb-2">تم استلام طلبك!</h2>
              <p className="text-white/60 text-sm">سيتم تجهيز طلبك قريباً</p>
              {tableNumber && <p className="text-[#E8637A] font-bold mt-3">طاولة رقم {tableNumber}</p>}
            </div>
          ) : (
            <>
              <h2 className="text-xl font-bold text-white mb-4">تأكيد الطلب</h2>
              <div className="space-y-3 mb-4">
                <div>
                  <Label className="text-white/70">اسمك (اختياري)</Label>
                  <Input value={customerName} onChange={e => setCustomerName(e.target.value)} placeholder="أدخل اسمك" className="bg-white/10 border-white/20 text-white placeholder-white/30 mt-1" data-testid="input-customer-name" />
                </div>
                <div>
                  <Label className="text-white/70">رقم الطاولة</Label>
                  <Input value={tableNumber} onChange={e => setTableNumber(e.target.value)} placeholder="مثال: 5" className="bg-white/10 border-white/20 text-white placeholder-white/30 mt-1" data-testid="input-table-number" />
                </div>
                <div>
                  <Label className="text-white/70">طريقة الدفع</Label>
                  <div className="grid grid-cols-2 gap-2 mt-1">
                    {[{ k: "cash", l: "نقداً" }, { k: "card", l: "بطاقة" }].map(m => (
                      <button key={m.k} onClick={() => setPaymentMethod(m.k)}
                        className={`p-3 rounded-xl text-sm font-bold transition-all ${paymentMethod === m.k ? "bg-[#E8637A] text-white" : "bg-white/10 text-white/60 hover:bg-white/20"}`}
                        data-testid={`payment-${m.k}`}>
                        {m.l}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              {/* Order summary */}
              <div className="bg-white/5 rounded-xl p-3 mb-4 space-y-1.5">
                {cart.map((item, i) => (
                  <div key={i} className="flex justify-between text-sm">
                    <span className="text-white/70">{item.product.nameAr || item.product.name} × {item.quantity}</span>
                    <span className="text-white font-bold">{(item.price * item.quantity).toFixed(2)}</span>
                  </div>
                ))}
                <div className="flex justify-between font-bold border-t border-white/10 pt-2 mt-2">
                  <span className="text-white">الإجمالي</span>
                  <span className="text-[#E8637A] text-lg">{cartTotal.toFixed(2)} ر.س</span>
                </div>
              </div>

              <div className="flex gap-2">
                <Button variant="ghost" className="flex-1 text-white/60" onClick={() => setShowCheckout(false)}>رجوع</Button>
                <Button onClick={placeOrder} disabled={isPlacing} className="flex-1 bg-[#E8637A] hover:bg-[#E8637A]/90 text-white font-bold" data-testid="button-place-order">
                  {isPlacing ? <Loader2 className="w-4 h-4 animate-spin ml-2" /> : null}
                  أرسل الطلب
                </Button>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>

      {/* Variant picker */}
      <Dialog open={!!selectedProduct} onOpenChange={() => setSelectedProduct(null)}>
        <DialogContent dir="rtl" className="max-w-sm bg-[#1a1108] text-white border border-white/10">
          {selectedProduct && (
            <>
              <h2 className="text-lg font-bold text-white">{selectedProduct.nameAr || selectedProduct.name}</h2>
              <p className="text-white/50 text-sm mb-3">اختر المقاس أو الخيار</p>
              <div className="space-y-2">
                {(selectedProduct.variants || []).map((v: any) => (
                  <button key={v.id || v._id} onClick={() => addToCart(selectedProduct, v)}
                    className="w-full flex items-center justify-between bg-white/10 hover:bg-white/20 border border-white/10 hover:border-[#E8637A]/40 rounded-xl p-3 transition-all"
                    data-testid={`variant-${v.id || v._id}`}>
                    <span className="font-bold text-white">{v.nameAr || v.name || v.size || v.label}</span>
                    <span className="text-[#E8637A] font-bold">{v.price} ر.س</span>
                  </button>
                ))}
                <button onClick={() => addToCart(selectedProduct)}
                  className="w-full flex items-center justify-between bg-white/5 hover:bg-white/10 border border-white/10 rounded-xl p-3 transition-all"
                  data-testid="variant-default">
                  <span className="text-white/70">الحجم الافتراضي</span>
                  <span className="text-[#E8637A] font-bold">{selectedProduct.price} ر.س</span>
                </button>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Link } from "wouter";
import { ArrowRight, Plus, Edit, Trash2, ChefHat, Loader2, X } from "lucide-react";

interface RawMaterial { id: string; nameAr: string; unit: string; unitCost: number; }
interface Recipe {
  id: string; productId: string; productName: string;
  ingredients: { rawMaterialId: string; rawMaterialName: string; quantity: number; unit: string; unitCost: number }[];
  totalCost: number; notes: string;
}
interface Product { id: string; name: string; nameAr?: string; }

const unitLabels: Record<string, string> = { g: "جرام", kg: "كيلو", ml: "مل", liter: "لتر", piece: "قطعة", box: "صندوق", bag: "كيس" };

export default function AdminRecipes() {
  const { toast } = useToast();
  const [showDialog, setShowDialog] = useState(false);
  const [editRecipe, setEditRecipe] = useState<Recipe | null>(null);
  const [selectedProduct, setSelectedProduct] = useState("");
  const [selectedProductName, setSelectedProductName] = useState("");
  const [notes, setNotes] = useState("");
  const [ingredients, setIngredients] = useState<{ rawMaterialId: string; rawMaterialName: string; quantity: number; unit: string; unitCost: number }[]>([]);
  const [selectedMat, setSelectedMat] = useState("");
  const [matQty, setMatQty] = useState(0);

  const { data: recipes = [], isLoading } = useQuery<Recipe[]>({ queryKey: ["/api/inventory/recipes"] });
  const { data: rawMaterials = [] } = useQuery<RawMaterial[]>({ queryKey: ["/api/inventory/raw-materials"] });
  const { data: products = [] } = useQuery<Product[]>({ queryKey: ["/api/products"] });

  const saveMutation = useMutation({
    mutationFn: (data: any) => {
      if (editRecipe) return apiRequest("PUT", `/api/inventory/recipes/${editRecipe.id}`, data);
      return apiRequest("POST", "/api/inventory/recipes", data);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/inventory/recipes"] });
      setShowDialog(false); resetForm();
      toast({ title: "تم حفظ الوصفة" });
    },
    onError: () => toast({ title: "خطأ", variant: "destructive" }),
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiRequest("DELETE", `/api/inventory/recipes/${id}`),
    onSuccess: () => { queryClient.invalidateQueries({ queryKey: ["/api/inventory/recipes"] }); toast({ title: "تم الحذف" }); },
  });

  function resetForm() {
    setEditRecipe(null); setSelectedProduct(""); setSelectedProductName(""); setNotes(""); setIngredients([]);
  }

  function openEdit(r: Recipe) {
    setEditRecipe(r);
    setSelectedProduct(r.productId);
    setSelectedProductName(r.productName);
    setNotes(r.notes);
    setIngredients(r.ingredients);
    setShowDialog(true);
  }

  function addIngredient() {
    if (!selectedMat || matQty <= 0) return;
    const mat = (rawMaterials as RawMaterial[]).find(m => m.id === selectedMat);
    if (!mat) return;
    const existing = ingredients.find(i => i.rawMaterialId === selectedMat);
    if (existing) { toast({ title: "هذه المادة مضافة بالفعل", variant: "destructive" }); return; }
    setIngredients(prev => [...prev, { rawMaterialId: mat.id, rawMaterialName: mat.nameAr, quantity: matQty, unit: mat.unit, unitCost: mat.unitCost }]);
    setSelectedMat(""); setMatQty(0);
  }

  function removeIngredient(idx: number) { setIngredients(prev => prev.filter((_, i) => i !== idx)); }

  const totalCost = ingredients.reduce((s, i) => s + i.quantity * i.unitCost, 0);

  function handleSave() {
    if (!selectedProduct) { toast({ title: "يرجى اختيار المنتج", variant: "destructive" }); return; }
    if (ingredients.length === 0) { toast({ title: "يرجى إضافة مكوّن واحد على الأقل", variant: "destructive" }); return; }
    saveMutation.mutate({ productId: selectedProduct, productName: selectedProductName, ingredients, notes, totalCost });
  }

  const getProductName = (id: string) => {
    const p = (products as Product[]).find(p => p.id === id);
    return p?.nameAr || p?.name || id;
  };

  return (
    <div className="min-h-screen bg-gray-50" dir="rtl">
      <div className="max-w-5xl mx-auto p-6 space-y-6">
        <div className="flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Link href="/admin"><Button variant="ghost" size="icon"><ArrowRight className="w-5 h-5" /></Button></Link>
            <div>
              <h1 className="text-2xl font-bold text-gray-900">وصفات المنتجات</h1>
              <p className="text-sm text-gray-500">ربط المنتجات بالمواد الخام المستهلكة</p>
            </div>
          </div>
          <Button onClick={() => { resetForm(); setShowDialog(true); }} className="bg-[#6B3F2A] hover:bg-[#6B3F2A]/90 text-white" data-testid="button-add-recipe">
            <Plus className="w-4 h-4 ml-1" /> إضافة وصفة
          </Button>
        </div>

        {isLoading ? (
          <div className="text-center py-12 text-gray-400">جاري التحميل...</div>
        ) : recipes.length === 0 ? (
          <div className="text-center py-12 text-gray-400">
            <ChefHat className="w-12 h-12 mx-auto mb-3 opacity-30" />
            <p>لا توجد وصفات محددة بعد</p>
          </div>
        ) : (
          <div className="space-y-4">
            {recipes.map(r => (
              <Card key={r.id} className="bg-white" data-testid={`card-recipe-${r.id}`}>
                <CardContent className="p-4">
                  <div className="flex items-start justify-between">
                    <div className="flex-1">
                      <h3 className="font-bold text-gray-900 mb-2 flex items-center gap-2">
                        <ChefHat className="w-4 h-4 text-[#6B3F2A]" />
                        {r.productName || getProductName(r.productId)}
                      </h3>
                      <div className="flex flex-wrap gap-2 mb-3">
                        {r.ingredients.map((ing, i) => (
                          <Badge key={i} variant="outline" className="text-xs">
                            {ing.rawMaterialName} — {ing.quantity} {unitLabels[ing.unit] || ing.unit}
                          </Badge>
                        ))}
                      </div>
                      <p className="text-sm text-gray-600">تكلفة الوصفة: <span className="font-bold text-[#6B3F2A]">{r.totalCost.toFixed(2)} ر.س</span></p>
                      {r.notes && <p className="text-xs text-gray-400 mt-1">{r.notes}</p>}
                    </div>
                    <div className="flex gap-1 shrink-0">
                      <Button size="icon" variant="ghost" className="h-8 w-8" onClick={() => openEdit(r)} data-testid={`button-edit-${r.id}`}><Edit className="w-3.5 h-3.5" /></Button>
                      <Button size="icon" variant="ghost" className="h-8 w-8 text-red-500" onClick={() => confirm("حذف هذه الوصفة؟") && deleteMutation.mutate(r.id)} data-testid={`button-delete-${r.id}`}><Trash2 className="w-3.5 h-3.5" /></Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            ))}
          </div>
        )}
      </div>

      <Dialog open={showDialog} onOpenChange={v => { setShowDialog(v); if (!v) resetForm(); }}>
        <DialogContent dir="rtl" className="max-w-lg">
          <DialogHeader><DialogTitle>{editRecipe ? "تعديل وصفة" : "إضافة وصفة جديدة"}</DialogTitle></DialogHeader>
          <div className="space-y-4 max-h-[70vh] overflow-y-auto">
            {/* Product selector */}
            <div>
              <Label>المنتج *</Label>
              <Select value={selectedProduct} onValueChange={v => {
                setSelectedProduct(v);
                const p = (products as Product[]).find(p => p.id === v);
                setSelectedProductName(p?.nameAr || p?.name || "");
              }}>
                <SelectTrigger data-testid="select-product"><SelectValue placeholder="اختر منتجاً" /></SelectTrigger>
                <SelectContent>
                  {(products as Product[]).map(p => (
                    <SelectItem key={p.id} value={p.id}>{p.nameAr || p.name}</SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Add ingredient */}
            <div className="bg-gray-50 rounded-xl p-3 space-y-2">
              <Label className="text-sm font-bold">إضافة مكوّن</Label>
              <div className="flex gap-2">
                <Select value={selectedMat} onValueChange={setSelectedMat}>
                  <SelectTrigger className="flex-1" data-testid="select-material"><SelectValue placeholder="المادة" /></SelectTrigger>
                  <SelectContent>
                    {(rawMaterials as RawMaterial[]).map(m => (
                      <SelectItem key={m.id} value={m.id}>{m.nameAr} ({unitLabels[m.unit] || m.unit})</SelectItem>
                    ))}
                  </SelectContent>
                </Select>
                <Input type="number" min="0" step="0.1" value={matQty || ""} onChange={e => setMatQty(Number(e.target.value))} placeholder="الكمية" className="w-24" data-testid="input-quantity" />
                <Button onClick={addIngredient} size="icon" className="bg-[#6B3F2A] text-white shrink-0" data-testid="button-add-ingredient"><Plus className="w-4 h-4" /></Button>
              </div>
            </div>

            {/* Ingredients list */}
            {ingredients.length > 0 && (
              <div className="space-y-2">
                <Label>المكونات</Label>
                {ingredients.map((ing, i) => (
                  <div key={i} className="flex items-center justify-between bg-white border border-gray-100 rounded-xl p-2.5" data-testid={`ingredient-${i}`}>
                    <span className="text-sm font-medium">{ing.rawMaterialName}</span>
                    <div className="flex items-center gap-3">
                      <span className="text-sm text-gray-600">{ing.quantity} {unitLabels[ing.unit] || ing.unit}</span>
                      <span className="text-xs text-gray-400">{(ing.quantity * ing.unitCost).toFixed(2)} ر.س</span>
                      <Button size="icon" variant="ghost" className="h-6 w-6 text-red-400" onClick={() => removeIngredient(i)} data-testid={`button-remove-ingredient-${i}`}><X className="w-3 h-3" /></Button>
                    </div>
                  </div>
                ))}
                <div className="text-left text-sm font-bold text-[#6B3F2A] pt-1">إجمالي التكلفة: {totalCost.toFixed(2)} ر.س</div>
              </div>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => { setShowDialog(false); resetForm(); }}>إلغاء</Button>
            <Button onClick={handleSave} disabled={saveMutation.isPending} className="bg-[#6B3F2A] text-white" data-testid="button-save-recipe">
              {saveMutation.isPending && <Loader2 className="w-4 h-4 animate-spin ml-2" />}
              {editRecipe ? "حفظ" : "إضافة"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

